export type ResourceKind = 'pod' | 'deployment' | 'service' | 'ingress' | 'configmap';
export interface Resource { id: string; kind: ResourceKind; name: string; namespace: string; status: 'healthy' | 'pending' | 'failed'; age: number; labels: Record<string, string>; ready?: { ready: number; desired: number }; }

// useLiveResources.ts
import { useEffect, useRef, useState } from 'react';
export function useLiveResources(ws: { subscribe: (cb: (r: Resource) => void) => () => void }) {
  const [version, setVersion] = useState(0);
  const map = useRef<Map<string, Resource>>(new Map());
  const pendingRender = useRef(false);
  useEffect(() => {
    return ws.subscribe((r) => {
      map.current.set(r.id, r);
      if (!pendingRender.current) {
        pendingRender.current = true;
        requestAnimationFrame(() => { pendingRender.current = false; setVersion(v => v + 1); });
      }
    });
  }, [ws]);
  return { resources: Array.from(map.current.values()), version };
}

// StatusGlyph.tsx
export function StatusGlyph({ status }: { status: Resource['status'] }) {
  if (status === 'healthy') return <span aria-label="healthy" className="inline-block w-1.5 h-1.5 bg-[oklch(0.6_0.14_145)] mr-2" />;
  if (status === 'pending') return <span aria-label="pending" className="inline-block w-1.5 h-1.5 border border-[oklch(0.75_0.16_80)] mr-2" />;
  return <span aria-label="failed" className="inline-block w-1.5 h-1.5 text-[oklch(0.6_0.18_25)] mr-2 leading-none text-[10px]">\u2715</span>;
}
import type { Resource } from './types';

// formatAge.ts
export function formatAge(ms: number): string {
  const s = Math.floor(ms / 1000);
  if (s < 60) return `${s}s`;
  const m = Math.floor(s / 60);
  if (m < 60) return `${m}m`;
  const h = Math.floor(m / 60);
  if (h < 24) return `${h}h`;
  return `${Math.floor(h / 24)}d`;
}

// ResourceExplorer.tsx
import { useCallback, useMemo, useRef, useState } from 'react';
import type { Resource, ResourceKind } from './types';
import { StatusGlyph } from './StatusGlyph';
import { formatAge } from './formatAge';

interface Props { resources: ReadonlyArray<Resource>; onTailLogs: (podId: string) => AsyncIterable<string>; }

export function ResourceExplorer({ resources, onTailLogs }: Props) {
  const [kind, setKind] = useState<ResourceKind>('pod');
  const [focusedId, setFocusedId] = useState<string | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [activeNs, setActiveNs] = useState<Set<string>>(new Set());
  const [labelFilters, setLabelFilters] = useState<Array<[string, string]>>([]);

  const namespaces = useMemo(() => Array.from(new Set(resources.map(r => r.namespace))).sort(), [resources]);
  const filtered = useMemo(() => resources.filter(r => r.kind === kind
    && (activeNs.size === 0 || activeNs.has(r.namespace))
    && labelFilters.every(([k, v]) => r.labels[k] === v)), [resources, kind, activeNs, labelFilters]);

  const onKey = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'j' || e.key === 'ArrowDown') {
      e.preventDefault();
      const idx = filtered.findIndex(r => r.id === focusedId);
      const next = filtered[Math.min(filtered.length - 1, idx + 1)];
      if (next) { setFocusedId(next.id); if (expandedId) setExpandedId(next.id); }
    } else if (e.key === 'k' || e.key === 'ArrowUp') {
      e.preventDefault();
      const idx = filtered.findIndex(r => r.id === focusedId);
      const next = filtered[Math.max(0, idx - 1)];
      if (next) { setFocusedId(next.id); if (expandedId) setExpandedId(next.id); }
    } else if (e.key === 'Enter' && focusedId) {
      e.preventDefault();
      setExpandedId(prev => prev === focusedId ? null : focusedId);
    }
  }, [filtered, focusedId, expandedId]);

  return (
    <div className="flex bg-[oklch(0.99_0.005_250)] text-[oklch(0.2_0.01_250)]" tabIndex={0} onKeyDown={onKey} role="grid" aria-label="Kubernetes resources">
      <NamespaceRail namespaces={namespaces} active={activeNs} onToggle={(n) => setActiveNs(s => { const x = new Set(s); if (x.has(n)) x.delete(n); else x.add(n); return x; })} />
      <div className="flex-1 min-w-0">
        <div className="flex gap-1 px-2 py-1 border-b border-[oklch(0.93_0.005_250)]">
          {(['pod','deployment','service','ingress','configmap'] as ResourceKind[]).map(k => (
            <button key={k} type="button" onClick={() => setKind(k)} className={`px-2 py-0.5 text-[11px] uppercase tracking-wider rounded ${kind === k ? 'bg-[oklch(0.2_0.01_250)] text-white' : 'text-[oklch(0.55_0.005_250)] hover:bg-[oklch(0.94_0.005_250)]'}`}>{k}s</button>
          ))}
          {labelFilters.length > 0 && (
            <div className="flex gap-1 ml-3">{labelFilters.map(([k, v], i) => (
              <button key={i} onClick={() => setLabelFilters(f => f.filter((_, j) => j !== i))} className="px-1.5 py-0.5 text-[10px] bg-[oklch(0.94_0.04_250)] text-[oklch(0.3_0.04_250)] rounded">{k}={v} \u00D7</button>
            ))}</div>
          )}
        </div>
        <div role="rowgroup">
          {filtered.map((r) => {
            const isFocus = r.id === focusedId;
            const isExpanded = r.id === expandedId;
            return (
              <div key={r.id}>
                <div role="row" aria-selected={isFocus} onClick={() => setFocusedId(r.id)}
                  className={`flex items-center h-[22px] px-2 font-mono text-[11.5px] cursor-pointer ${isFocus ? 'bg-[oklch(0.94_0.04_250)]' : 'hover:bg-[oklch(0.97_0.005_250)]'}`}>
                  <StatusGlyph status={r.status} />
                  <span className="flex-1 truncate">{r.name}</span>
                  <span className="w-20 text-right text-[oklch(0.55_0.005_250)]">{r.namespace}</span>
                  <span className="w-12 text-right tabular-nums text-[oklch(0.55_0.005_250)]">{r.ready ? `${r.ready.ready}/${r.ready.desired}` : ''}</span>
                  <span className="w-10 text-right tabular-nums text-[oklch(0.55_0.005_250)]">{formatAge(r.age)}</span>
                  <span className="ml-3 flex gap-1">{Object.entries(r.labels).slice(0, 3).map(([k, v]) => (
                    <button key={k} type="button" onClick={(e) => { e.stopPropagation(); setLabelFilters(f => [...f, [k, v]]); }} className="text-[10px] text-[oklch(0.55_0.005_250)] hover:text-[oklch(0.3_0.005_250)]"><span className="opacity-70">{k}</span>={v}</button>
                  ))}</span>
                </div>
                {isExpanded && (
                  <div role="region" aria-label="Inline logs" className="bg-[oklch(0.16_0.005_250)] text-[oklch(0.85_0.01_250)] font-mono text-[11px] p-2 max-h-[240px] overflow-y-auto" style={{ animation: 'logExpand 250ms cubic-bezier(0.22, 1, 0.36, 1)' }}>
                    <InlineLogs podId={r.id} onTail={onTailLogs} />
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
      <style>{`@keyframes logExpand { from { max-height: 0; opacity: 0 } to { max-height: 240px; opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='logExpand'] { animation: none !important } }`}</style>
    </div>
  );
}

function NamespaceRail({ namespaces, active, onToggle }: { namespaces: ReadonlyArray<string>; active: Set<string>; onToggle: (n: string) => void }) {
  return (
    <nav aria-label="Namespaces" className="w-32 border-r border-[oklch(0.93_0.005_250)] py-2">
      {namespaces.map((n) => {
        const isActive = active.has(n);
        const hash = Array.from(n).reduce((a, c) => a + c.charCodeAt(0), 0);
        const color = `oklch(0.65 0.16 ${(hash * 31) % 360})`;
        return (
          <button key={n} type="button" onClick={() => onToggle(n)} className={`w-full text-left flex items-center gap-2 px-2 py-1 text-[12px] ${isActive ? 'bg-[oklch(0.97_0.005_250)] text-[oklch(0.2_0.01_250)]' : 'text-[oklch(0.55_0.005_250)] hover:bg-[oklch(0.97_0.005_250)]'}`}>
            <span className="w-1 h-4" style={{ background: isActive ? color : 'transparent' }} />
            {n}
          </button>
        );
      })}
    </nav>
  );
}

function InlineLogs({ podId, onTail }: { podId: string; onTail: (id: string) => AsyncIterable<string> }) {
  const [lines, setLines] = useState<string[]>([]);
  const containerRef = useRef<HTMLDivElement | null>(null);
  // simplified: in real impl, cancel on unmount/podId change
  return (
    <div ref={containerRef} aria-live="polite" aria-relevant="additions">
      {lines.map((l, i) => <div key={i}>{l}</div>)}
    </div>
  );
}

import { useEffect, useRef } from 'react';
export interface Action { kind: string; data?: unknown; }
export function useShortcutGrammar(handler: (action: Action) => void) {
  const chordBuffer = useRef<string>('');
  const chordTimer = useRef<number | null>(null);
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.metaKey || e.ctrlKey || e.altKey) return;
      const key = e.key;
      // single-char verbs
      const single: Record<string, string> = { e: 'archive', '#': 'delete', r: 'reply', R: 'reply-all', f: 'forward', l: 'label', s: 'snooze', y: 'toggle-read', m: 'mute', z: 'undo', j: 'next', k: 'prev', o: 'toggle-open', Enter: 'open', Escape: 'close' };
      // chord starts
      if (key === 'g') {
        chordBuffer.current = 'g';
        if (chordTimer.current) window.clearTimeout(chordTimer.current);
        chordTimer.current = window.setTimeout(() => { chordBuffer.current = ''; }, 800);
        return;
      }
      if (chordBuffer.current === 'g') {
        const dest: Record<string, string> = { i: 'inbox', s: 'starred', d: 'drafts', a: 'all' };
        if (dest[key]) { handler({ kind: 'goto', data: dest[key] }); chordBuffer.current = ''; if (chordTimer.current) window.clearTimeout(chordTimer.current); e.preventDefault(); return; }
      }
      if (single[key]) { handler({ kind: single[key] }); e.preventDefault(); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [handler]);
}

// useUndoQueue.ts
import { useCallback, useState } from 'react';
export interface UndoEntry<TOp> { id: string; label: string; expiresAt: number; revert: () => void; op: TOp; }
export function useUndoQueue<TOp>() {
  const [queue, setQueue] = useState<ReadonlyArray<UndoEntry<TOp>>>([]);
  const push = useCallback((entry: Omit<UndoEntry<TOp>, 'id' | 'expiresAt'>) => {
    const full: UndoEntry<TOp> = { ...entry, id: crypto.randomUUID(), expiresAt: Date.now() + 5000 };
    setQueue(q => [...q, full]);
    window.setTimeout(() => setQueue(q => q.filter(e => e.id !== full.id)), 5000);
  }, []);
  const undo = useCallback(() => {
    setQueue(q => {
      const last = q[q.length - 1];
      if (last) last.revert();
      return q.slice(0, -1);
    });
  }, []);
  return { queue, push, undo, top: queue[queue.length - 1] ?? null };
}

// EmailTriage.tsx
import { useCallback, useState } from 'react';
import { useShortcutGrammar } from './useShortcutGrammar';
import { useUndoQueue } from './useUndoQueue';

interface Thread { id: string; from: string; subject: string; preview: string; unread: boolean; archived: boolean; }
interface Props { initialThreads: ReadonlyArray<Thread>; }

export function EmailTriage({ initialThreads }: Props) {
  const [threads, setThreads] = useState<ReadonlyArray<Thread>>(initialThreads);
  const [focusedId, setFocusedId] = useState<string | null>(initialThreads[0]?.id ?? null);
  const [openedId, setOpenedId] = useState<string | null>(null);
  const [snoozeOpen, setSnoozeOpen] = useState(false);
  const { push: pushUndo, undo, top: undoTop } = useUndoQueue<{ kind: string; threadId: string }>();

  const visible = threads.filter(t => !t.archived);

  const handler = useCallback((action: { kind: string; data?: unknown }) => {
    if (action.kind === 'next' || action.kind === 'prev') {
      const idx = visible.findIndex(t => t.id === focusedId);
      const next = visible[action.kind === 'next' ? Math.min(visible.length - 1, idx + 1) : Math.max(0, idx - 1)];
      if (next) setFocusedId(next.id);
    } else if (action.kind === 'archive' && focusedId) {
      const before = threads;
      setThreads(ts => ts.map(t => t.id === focusedId ? { ...t, archived: true } : t));
      pushUndo({ label: 'Archived', revert: () => setThreads(before), op: { kind: 'archive', threadId: focusedId } });
      const nextIdx = visible.findIndex(t => t.id === focusedId) + 1;
      setFocusedId(visible[nextIdx]?.id ?? visible[nextIdx - 1]?.id ?? null);
    } else if (action.kind === 'snooze') {
      setSnoozeOpen(true);
    } else if (action.kind === 'undo') {
      undo();
    } else if (action.kind === 'toggle-open' || action.kind === 'open') {
      setOpenedId(prev => prev === focusedId ? null : focusedId);
    } else if (action.kind === 'close') {
      setOpenedId(null);
      setSnoozeOpen(false);
    }
  }, [focusedId, visible, threads, pushUndo, undo]);

  useShortcutGrammar(handler);

  return (
    <div className="flex h-screen bg-[oklch(0.99_0.005_250)]">
      <ul className="flex-1 max-w-[480px] border-r border-[oklch(0.93_0.005_250)] overflow-y-auto" role="listbox" aria-label="Threads">
        {visible.map(t => {
          const isFocus = t.id === focusedId;
          return (
            <li key={t.id} role="option" aria-selected={isFocus} onClick={() => setFocusedId(t.id)}
              className={`relative h-12 px-4 py-1.5 cursor-pointer flex flex-col justify-center ${isFocus ? 'bg-[oklch(0.97_0.005_250)]' : ''}`}
              style={{ borderLeft: isFocus ? '2px solid oklch(0.55 0.18 250)' : '2px solid transparent', transition: 'opacity 100ms ease-out' }}>
              <div className="flex items-center gap-2">
                {t.unread && <span aria-label="unread" className="w-1.5 h-1.5 rounded-full bg-[oklch(0.55_0.18_250)] shrink-0" />}
                <span className={`text-[14px] flex-1 truncate ${t.unread ? 'font-medium' : 'text-[oklch(0.45_0.005_250)]'}`}>{t.from}</span>
              </div>
              <div className={`text-[13px] truncate ${t.unread ? 'text-[oklch(0.2_0.01_250)]' : 'text-[oklch(0.55_0.005_250)]'}`}><span className="font-medium">{t.subject}</span> <span className="text-[oklch(0.55_0.005_250)]">— {t.preview}</span></div>
            </li>
          );
        })}
      </ul>
      <main className="flex-1 p-6" aria-label="Thread reading pane">
        {openedId ? <div>Thread {openedId} reading content here.</div> : <div className="text-[oklch(0.55_0.005_250)] text-[13px]">Press Enter or o to open the focused thread.</div>}
      </main>
      <div className="fixed bottom-0 left-0 right-0 h-8 bg-[oklch(0.18_0.005_250_/_0.92)] backdrop-blur text-white text-[12px] flex items-center justify-center gap-4 font-mono">
        <span><kbd className="opacity-70">E</kbd> archive</span>
        <span><kbd className="opacity-70">#</kbd> delete</span>
        <span><kbd className="opacity-70">R</kbd> reply</span>
        <span><kbd className="opacity-70">S</kbd> snooze</span>
        <span><kbd className="opacity-70">L</kbd> label</span>
      </div>
      {undoTop && (
        <div role="status" aria-live="polite" className="fixed bottom-12 left-1/2 -translate-x-1/2 px-3 py-1.5 rounded-full bg-[oklch(0.18_0.005_250_/_0.92)] text-white text-[12px]" style={{ animation: 'undoIn 120ms ease-out' }}>{undoTop.label} <span className="opacity-70 font-mono">\u00B7 z to undo</span></div>
      )}
      <style>{`@keyframes undoIn { from { opacity: 0; transform: translate(-50%, 4px) } to { opacity: 1; transform: translate(-50%, 0) } } @media (prefers-reduced-motion: reduce) { [style*='undoIn'] { animation: none !important } }`}</style>
    </div>
  );
}

export interface FrameComment { id: string; videoTimeMs: number; authorId: string; authorName: string; authorColorIdx: number; body: string; createdAt: number; parentId: string | null; drawing?: { x: number; y: number; w: number; h: number }; }

// useTimelineCursor.ts
import { useEffect, useRef, useState } from 'react';
export function useTimelineCursor() {
  const [cursor, setCursor] = useState<{ x: number; pct: number } | null>(null);
  const trackRef = useRef<HTMLDivElement | null>(null);
  useEffect(() => {
    const el = trackRef.current; if (!el) return;
    const onMove = (e: PointerEvent) => {
      const r = el.getBoundingClientRect();
      if (e.clientX < r.left || e.clientX > r.right) { setCursor(null); return; }
      setCursor({ x: e.clientX - r.left, pct: (e.clientX - r.left) / r.width });
    };
    const onLeave = () => setCursor(null);
    el.addEventListener('pointermove', onMove);
    el.addEventListener('pointerleave', onLeave);
    return () => { el.removeEventListener('pointermove', onMove); el.removeEventListener('pointerleave', onLeave); };
  }, []);
  return { trackRef, cursor };
}

// Timeline.tsx
import { useMemo } from 'react';
import type { FrameComment } from './types';
import { useTimelineCursor } from './useTimelineCursor';

const PALETTE = ['oklch(0.65 0.18 25)','oklch(0.7 0.16 145)','oklch(0.6 0.2 280)','oklch(0.72 0.15 60)','oklch(0.62 0.19 200)','oklch(0.68 0.17 320)','oklch(0.66 0.16 100)','oklch(0.6 0.2 0)','oklch(0.7 0.14 240)','oklch(0.64 0.18 50)','oklch(0.66 0.17 170)','oklch(0.62 0.19 300)'];

interface Props { durationMs: number; currentTimeMs: number; comments: ReadonlyArray<FrameComment>; spriteSheetUrl: string; spriteIntervalMs: number; onSeek: (ms: number) => void; onSelectComment: (id: string) => void; }

export function Timeline({ durationMs, currentTimeMs, comments, spriteSheetUrl, spriteIntervalMs, onSeek, onSelectComment }: Props) {
  const { trackRef, cursor } = useTimelineCursor();
  const playheadPct = currentTimeMs / durationMs;

  const clusters = useMemo(() => {
    const sorted = [...comments].sort((a, b) => a.videoTimeMs - b.videoTimeMs);
    const out: Array<{ comments: FrameComment[]; pct: number }> = [];
    const PIXEL_THRESHOLD_PCT = 0.012;
    for (const c of sorted) {
      const pct = c.videoTimeMs / durationMs;
      const last = out[out.length - 1];
      if (last && Math.abs(last.pct - pct) < PIXEL_THRESHOLD_PCT) last.comments.push(c);
      else out.push({ comments: [c], pct });
    }
    return out;
  }, [comments, durationMs]);

  const hoverFrameIdx = cursor ? Math.floor((cursor.pct * durationMs) / spriteIntervalMs) : null;

  return (
    <div className="relative" style={{ height: 56 }}>
      <div ref={trackRef} className="absolute bottom-0 left-0 right-0 h-8 bg-[oklch(0.85_0.005_250)] cursor-pointer"
        onClick={(e) => { const r = e.currentTarget.getBoundingClientRect(); onSeek(((e.clientX - r.left) / r.width) * durationMs); }}>
        <div className="absolute top-0 bottom-0 bg-[oklch(0.55_0.18_250)] w-0.5" style={{ left: `${playheadPct * 100}%` }} />
        {clusters.map((cl, i) => (
          <button key={i} type="button" onClick={(e) => { e.stopPropagation(); onSelectComment(cl.comments[0].id); onSeek(cl.comments[0].videoTimeMs); }}
            className="absolute top-0 bottom-0 px-1 cursor-pointer" style={{ left: `${cl.pct * 100}%`, transform: 'translateX(-50%)' }}
            aria-label={`${cl.comments.length} comment(s) at ${(cl.comments[0].videoTimeMs / 1000).toFixed(1)}s`}>
            <div className="w-1 h-full" style={{ background: PALETTE[cl.comments[0].authorColorIdx % PALETTE.length] }} />
            {cl.comments.length > 1 && <span className="absolute -top-4 left-1/2 -translate-x-1/2 text-[10px] tabular-nums bg-[oklch(0.2_0.01_250)] text-white px-1 rounded">{cl.comments.length}</span>}
          </button>
        ))}
      </div>
      {cursor && hoverFrameIdx != null && (
        <div className="absolute bottom-9 pointer-events-none" style={{ left: cursor.x - 48 }}>
          <div className="w-24 h-[54px] bg-no-repeat bg-cover overflow-hidden rounded shadow-lg relative" style={{ backgroundImage: `url(${spriteSheetUrl})`, backgroundPosition: `${-hoverFrameIdx * 96}px 0`, backgroundSize: 'auto 54px' }}>
            <span className="absolute bottom-0 left-0 right-0 text-center text-[10px] font-mono text-white bg-black/40">{(cursor.pct * durationMs / 1000).toFixed(1)}s</span>
          </div>
        </div>
      )}
    </div>
  );
}

// CommentThread.tsx
import type { FrameComment } from './types';

export function CommentThread({ root, replies, spriteSheetUrl, spriteIntervalMs, onSeek }: { root: FrameComment; replies: ReadonlyArray<FrameComment>; spriteSheetUrl: string; spriteIntervalMs: number; onSeek: (ms: number) => void }) {
  const frameIdx = Math.floor(root.videoTimeMs / spriteIntervalMs);
  return (
    <article className="py-3 border-b border-[oklch(0.93_0.005_250)]">
      <header className="flex items-center gap-3">
        <button type="button" onClick={() => onSeek(root.videoTimeMs)} className="shrink-0 w-12 h-[28px] bg-no-repeat bg-cover rounded overflow-hidden ring-1 ring-black/5" style={{ backgroundImage: `url(${spriteSheetUrl})`, backgroundPosition: `${-frameIdx * 48}px 0`, backgroundSize: 'auto 28px' }} aria-label={`Seek to ${(root.videoTimeMs / 1000).toFixed(1)}s`} />
        <div>
          <div className="text-[13px] font-medium">{root.authorName}</div>
          <div className="text-[11px] tabular-nums text-[oklch(0.55_0.005_250)]">{(root.videoTimeMs / 1000).toFixed(1)}s</div>
        </div>
      </header>
      <p className="text-[14px] leading-[22px] mt-2">{root.body}</p>
      {replies.length > 0 && (
        <div className="mt-2 ml-3 pl-3 border-l border-[oklch(0.93_0.005_250)]">
          {replies.slice(0, 5).map(r => (
            <div key={r.id} className="mt-2">
              <div className="text-[12px] font-medium">{r.authorName}</div>
              <p className="text-[13px] leading-[20px]">{r.body}</p>
            </div>
          ))}
          {replies.length > 5 && <button type="button" className="text-[12px] text-[oklch(0.55_0.18_250)] mt-2">View {replies.length - 5} more replies</button>}
        </div>
      )}
    </article>
  );
}

export function holdMsForAmount(amount: number): number {
  if (amount >= 1000) return 0; // biometric instead
  if (amount >= 50) return 2500;
  return 1500;
}

// usePressAndHold.ts
import { useCallback, useEffect, useRef, useState } from 'react';
export function usePressAndHold(durationMs: number, onComplete: () => void) {
  const [progress, setProgress] = useState(0);
  const [holding, setHolding] = useState(false);
  const startRef = useRef<number | null>(null);
  const rafRef = useRef<number | null>(null);
  const halfHaptic = useRef(false);

  const tick = useCallback(() => {
    if (startRef.current == null) return;
    const elapsed = performance.now() - startRef.current;
    const f = Math.min(1, elapsed / durationMs);
    setProgress(f);
    if (f >= 0.5 && !halfHaptic.current) { halfHaptic.current = true; if ('vibrate' in navigator) navigator.vibrate(8); }
    if (f >= 1) { onComplete(); startRef.current = null; setHolding(false); return; }
    rafRef.current = requestAnimationFrame(tick);
  }, [durationMs, onComplete]);

  const start = useCallback(() => {
    startRef.current = performance.now();
    halfHaptic.current = false;
    setHolding(true);
    rafRef.current = requestAnimationFrame(tick);
  }, [tick]);

  const cancel = useCallback(() => {
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
    startRef.current = null;
    setHolding(false);
    // animate progress back to 0
    let p = progress;
    const start = performance.now();
    const animate = () => {
      const elapsed = performance.now() - start;
      const next = p * (1 - Math.min(1, elapsed / 200));
      setProgress(next);
      if (elapsed < 200) requestAnimationFrame(animate);
      else setProgress(0);
    };
    requestAnimationFrame(animate);
  }, [progress]);

  useEffect(() => () => { if (rafRef.current) cancelAnimationFrame(rafRef.current); }, []);
  return { progress, holding, start, cancel };
}

// SendButton.tsx
import { useCallback, useState } from 'react';
import { usePressAndHold } from './usePressAndHold';
import { holdMsForAmount } from './thresholds';

type Status = 'idle' | 'sending' | 'sent' | 'failed';
interface Props { amount: number; currency: string; recipient: string; onSend: () => Promise<{ ok: true; receiptId: string } | { ok: false; reason: string }>; }

export function SendButton({ amount, currency, recipient, onSend }: Props) {
  const [status, setStatus] = useState<Status>('idle');
  const [error, setError] = useState<string | null>(null);
  const durationMs = holdMsForAmount(amount);
  const requiresBiometric = durationMs === 0;

  const fire = useCallback(async () => {
    setStatus('sending');
    const res = await onSend();
    if (res.ok) setStatus('sent');
    else { setError(res.reason); setStatus('failed'); }
  }, [onSend]);

  const hold = usePressAndHold(durationMs || 1, fire);

  const onPointerDown = () => { if (requiresBiometric) fire(); else hold.start(); };

  const fmt = `${currency === 'USD' ? '$' : currency} ${amount.toFixed(2)}`;

  if (status === 'sent') {
    return (
      <div className="w-full">
        <button type="button" disabled className="w-full h-12 rounded-lg bg-[oklch(0.55_0.16_145)] text-white text-[15px] font-medium flex items-center justify-center gap-2 transition-colors duration-[300ms]">
          <CheckIcon /> Sent \u00B7 {fmt} to {recipient}
        </button>
        <a href="#" className="block mt-3 text-[13px] underline underline-offset-2 text-[oklch(0.45_0.005_250)]" style={{ animation: 'rcptIn 200ms ease-out 4000ms backwards' }}>View receipt</a>
        <style>{`@keyframes rcptIn { from { opacity: 0; transform: translateY(4px) } to { opacity: 1; transform: translateY(0) } }`}</style>
      </div>
    );
  }

  if (status === 'failed') {
    return (
      <div className="w-full">
        <button type="button" onClick={() => { setStatus('idle'); setError(null); }} className="w-full h-12 rounded-lg bg-[oklch(0.6_0.18_25)] text-white text-[15px] font-medium flex items-center justify-center gap-2">
          <XIcon /> Couldn\u2019t send \u00B7 {error}
        </button>
      </div>
    );
  }

  return (
    <button type="button" onPointerDown={onPointerDown} onPointerUp={hold.cancel} onPointerLeave={hold.cancel}
      aria-label={requiresBiometric ? `Send ${fmt} to ${recipient} with biometric authentication` : `Hold to send ${fmt} to ${recipient}`}
      className="relative w-full h-12 rounded-lg bg-[oklch(0.55_0.18_250)] text-white text-[15px] font-medium overflow-hidden">
      <span aria-hidden="true" className="absolute inset-y-0 left-0 bg-[oklch(0.4_0.18_250_/_0.3)]" style={{ width: `${hold.progress * 100}%`, transition: hold.holding ? 'none' : 'width 200ms ease-out' }} />
      <span className="relative">{requiresBiometric ? `Authenticate to send ${fmt}` : `Hold to send ${fmt} to ${recipient}`}</span>
    </button>
  );
}

function CheckIcon() { return <svg width="16" height="16" viewBox="0 0 16 16" aria-hidden="true"><path d="M3 8 L7 12 L13 4" stroke="currentColor" strokeWidth="2" fill="none" strokeLinecap="round" /></svg>; }
function XIcon() { return <svg width="16" height="16" viewBox="0 0 16 16" aria-hidden="true"><path d="M4 4 L12 12 M12 4 L4 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" /></svg>; }

export function divergingColor(value: number, midpoint: number, scale: number): string {
  const t = Math.max(-1, Math.min(1, (value - midpoint) / scale));
  if (t === 0) return 'oklch(0.95 0.005 250)';
  const lightness = 0.95 - Math.abs(t) * 0.4;
  const chroma = 0.02 + Math.abs(t) * 0.16;
  const hue = t < 0 ? 250 : 25;
  return `oklch(${lightness.toFixed(3)} ${chroma.toFixed(3)} ${hue})`;
}

// useViewBoxTween.ts
import { useEffect, useRef, useState } from 'react';
export function useViewBoxTween(target: [number, number, number, number], durationMs = 600) {
  const [current, setCurrent] = useState(target);
  const startRef = useRef<{ from: typeof target; to: typeof target; t0: number } | null>(null);
  useEffect(() => {
    startRef.current = { from: current, to: target, t0: performance.now() };
    let raf = 0;
    const tick = () => {
      const s = startRef.current; if (!s) return;
      const t = Math.min(1, (performance.now() - s.t0) / durationMs);
      const eased = 1 - Math.pow(1 - t, 3); // ease-out cubic
      const next: typeof target = [0,0,0,0];
      for (let i = 0; i < 4; i++) next[i] = s.from[i] + (s.to[i] - s.from[i]) * eased;
      setCurrent(next);
      if (t < 1) raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [target.join(','), durationMs]);
  return current;
}

// Choropleth.tsx
import { useCallback, useMemo, useState } from 'react';
import { divergingColor } from './scale';
import { useViewBoxTween } from './useViewBoxTween';

export interface GeoFeature { id: string; name: string; path: string; bbox: [number, number, number, number]; centroid: [number, number]; }

interface Props { features: ReadonlyArray<GeoFeature>; values: ReadonlyMap<string, number>; midpoint: number; scale: number; defaultBbox: [number, number, number, number]; nationalMean: number; }

export function Choropleth({ features, values, midpoint, scale, defaultBbox, nationalMean }: Props) {
  const [focusedId, setFocusedId] = useState<string | null>(null);
  const targetBbox = useMemo<[number, number, number, number]>(() => {
    if (!focusedId) return defaultBbox;
    const f = features.find(x => x.id === focusedId);
    if (!f) return defaultBbox;
    const [x, y, w, h] = f.bbox;
    const pad = Math.max(w, h) * 0.15;
    return [x - pad, y - pad, w + 2 * pad, h + 2 * pad];
  }, [focusedId, features, defaultBbox]);
  const viewBox = useViewBoxTween(targetBbox);
  const [hover, setHover] = useState<string | null>(null);

  const handleClick = useCallback((id: string) => { setFocusedId(prev => prev === id ? null : id); }, []);

  return (
    <div className="relative w-full h-full" onKeyDown={(e) => { if (e.key === 'Escape') setFocusedId(null); }} tabIndex={0}>
      <svg viewBox={viewBox.join(' ')} className="w-full h-full" role="img" aria-label="Geographic data map">
        {features.map(f => {
          const v = values.get(f.id);
          const fill = v == null ? 'oklch(0.93 0.005 250)' : divergingColor(v, midpoint, scale);
          const dim = focusedId && focusedId !== f.id;
          return (
            <path key={f.id} d={f.path} fill={fill} stroke="oklch(0.99 0.005 250)" strokeWidth="0.5"
              style={{ opacity: dim ? 0.3 : 1, transition: 'fill 300ms ease-out, opacity 200ms ease-out', cursor: 'pointer' }}
              onClick={() => handleClick(f.id)}
              onMouseEnter={() => setHover(f.id)} onMouseLeave={() => setHover(null)}
              aria-label={`${f.name}: ${v != null ? v.toFixed(1) : 'no data'}`} />
          );
        })}
      </svg>
      {hover && (() => {
        const f = features.find(x => x.id === hover); if (!f) return null;
        const v = values.get(f.id);
        const diff = v != null ? v - nationalMean : null;
        return (
          <div className="absolute top-4 left-4 bg-white shadow-lg rounded p-3 text-[13px]" role="status">
            <div className="font-medium">{f.name}</div>
            {v != null && (
              <div className="text-[11px] text-[oklch(0.55_0.005_250)] mt-1">
                {v.toFixed(1)} {diff != null && <span>\u00B7 {diff >= 0 ? '+' : ''}{diff.toFixed(1)} pp vs national</span>}
              </div>
            )}
          </div>
        );
      })()}
    </div>
  );
}

import { createContext, useCallback, useContext, useEffect, useState } from 'react';
export type SetupStep = 'invite-teammate' | 'create-project' | 'connect-slack' | 'configure-calendar';
const ALL_STEPS: ReadonlyArray<SetupStep> = ['invite-teammate', 'create-project', 'connect-slack', 'configure-calendar'];
interface Ctx { completed: Set<SetupStep>; complete: (s: SetupStep) => void; sessionsSinceStart: number; }
const C = createContext<Ctx | null>(null);
const KEY = 'setup-state-v1';
export function SetupProvider({ children }: { children: React.ReactNode }) {
  const [completed, setCompleted] = useState<Set<SetupStep>>(() => {
    try { const raw = localStorage.getItem(KEY); return new Set(raw ? JSON.parse(raw) : []); } catch { return new Set(); }
  });
  const [sessionsSinceStart, setSessions] = useState(0);
  useEffect(() => {
    const cnt = Number(localStorage.getItem('session-count') || '0') + 1;
    localStorage.setItem('session-count', String(cnt));
    setSessions(cnt);
  }, []);
  const complete = useCallback((s: SetupStep) => {
    setCompleted(prev => {
      const next = new Set(prev); next.add(s);
      try { localStorage.setItem(KEY, JSON.stringify(Array.from(next))); } catch {}
      return next;
    });
  }, []);
  return <C.Provider value={{ completed, complete, sessionsSinceStart }}>{children}</C.Provider>;
}
export function useSetup() { const v = useContext(C); if (!v) throw new Error('provider'); return v; }
export function useIncompleteSteps(): ReadonlyArray<SetupStep> { const { completed } = useSetup(); return ALL_STEPS.filter(s => !completed.has(s)); }

