// useFieldFlip.ts (FLIP for field reflow)
import { useLayoutEffect, useRef } from 'react';
export function useFieldFlip(deps: ReadonlyArray<unknown>) {
  const refs = useRef<Map<string, HTMLElement>>(new Map());
  const lastBoxes = useRef<Map<string, DOMRect>>(new Map());
  useLayoutEffect(() => {
    const newBoxes = new Map<string, DOMRect>();
    refs.current.forEach((el, id) => newBoxes.set(id, el.getBoundingClientRect()));
    refs.current.forEach((el, id) => {
      const last = lastBoxes.current.get(id);
      const next = newBoxes.get(id);
      if (!last || !next) return;
      const dx = last.left - next.left;
      const dy = last.top - next.top;
      if (dx !== 0 || dy !== 0) {
        el.style.transform = `translate(${dx}px, ${dy}px)`;
        el.style.transition = 'none';
        requestAnimationFrame(() => {
          el.style.transition = 'transform 300ms cubic-bezier(0.22, 1, 0.36, 1)';
          el.style.transform = 'translate(0, 0)';
        });
      }
    });
    lastBoxes.current = newBoxes;
  }, deps);
  return refs;
}

