// snap.ts
export function snapToGrid(pos: [number, number, number], unit = 1): [number, number, number] {
  return [Math.round(pos[0] / unit) * unit, pos[1], Math.round(pos[2] / unit) * unit];
}
export function snapRotation(rotRadians: number, stepDeg = 15): number {
  const deg = (rotRadians * 180) / Math.PI;
  const snapped = Math.round(deg / stepDeg) * stepDeg;
  return (snapped * Math.PI) / 180;
}
export function nearestSnapAngle(camYawRadians: number): number {
  const deg = ((camYawRadians * 180) / Math.PI + 360) % 360;
  const snapped = Math.round(deg / 45) * 45;
  return (snapped * Math.PI) / 180;
}

// SunSystem.tsx
import { useMemo } from 'react';
import { DirectionalLight, Vector3 } from 'three';
import { useThree } from '@react-three/fiber';

export function SunSystem({ timeOfDay }: { timeOfDay: number }) {
  // timeOfDay: 6 to 18 (6am to 6pm)
  const angle = ((timeOfDay - 12) / 12) * Math.PI; // -π/2 to π/2 across the day
  const dir = useMemo(() => new Vector3(Math.cos(angle), Math.sin(angle + Math.PI / 2), 0.3).normalize().multiplyScalar(20), [angle]);
  return (
    <>
      <ambientLight intensity={0.4} />
      <directionalLight position={[dir.x, dir.y, dir.z]} intensity={0.9} castShadow shadow-mapSize-width={1024} shadow-mapSize-height={1024} />
    </>
  );
}

// PlacementGhost.tsx
import { useFrame, useThree } from '@react-three/fiber';
import { useRef } from 'react';
import { Vector3, Raycaster, Plane } from 'three';
import { snapToGrid } from './snap';

export function PlacementGhost({ kind, onPlace }: { kind: string | null; onPlace: (pos: [number, number, number]) => void }) {
  const { camera, gl, scene } = useThree();
  const ghostRef = useRef<any>(null);
  const raycaster = useRef(new Raycaster());
  const groundPlane = useRef(new Plane(new Vector3(0, 1, 0), 0));
  const cursorWorld = useRef<[number, number, number]>([0, 0, 0]);

  useFrame(({ pointer }) => {
    if (!kind) return;
    raycaster.current.setFromCamera(pointer, camera);
    const target = new Vector3();
    raycaster.current.ray.intersectPlane(groundPlane.current, target);
    const snapped = snapToGrid([target.x, target.y, target.z]);
    cursorWorld.current = snapped;
    if (ghostRef.current) ghostRef.current.position.set(...snapped);
  });

  if (!kind) return null;
  return (
    <mesh ref={ghostRef} onClick={() => onPlace(cursorWorld.current)}>
      <boxGeometry args={[1, 1, 1]} />
      <meshStandardMaterial color="oklch(0.55 0.18 250)" transparent opacity={0.5} />
    </mesh>
  );
}

