import { useEffect, useState } from 'react';
export function useInputModality(): 'touch' | 'mouse' {
  const [m, setM] = useState<'touch' | 'mouse'>(() => typeof window !== 'undefined' && matchMedia('(hover: none)').matches ? 'touch' : 'mouse');
  useEffect(() => {
    const on = (e: PointerEvent) => setM(e.pointerType === 'touch' || e.pointerType === 'pen' ? 'touch' : 'mouse');
    window.addEventListener('pointerdown', on);
    return () => window.removeEventListener('pointerdown', on);
  }, []);
  return m;
}

