import { useEffect, useRef, useState } from 'react';

interface Options { count: number; autoAdvanceMs?: number; }

export function useCarousel({ count, autoAdvanceMs }: Options) {
  const [index, setIndex] = useState(0);
  const [userPaused, setUserPaused] = useState(false);
  const [politePaused, setPolitePaused] = useState(false);
  const [reducedMotion] = useState(() => typeof window !== 'undefined' && matchMedia('(prefers-reduced-motion: reduce)').matches);
  const timerRef = useRef<number | null>(null);

  const next = () => setIndex(i => (i + 1) % count);
  const prev = () => setIndex(i => (i - 1 + count) % count);
  const goTo = (i: number) => setIndex(Math.max(0, Math.min(count - 1, i)));

  const isPaused = userPaused || politePaused || reducedMotion;

  useEffect(() => {
    if (!autoAdvanceMs || isPaused) return;
    timerRef.current = window.setTimeout(next, autoAdvanceMs);
    return () => { if (timerRef.current) window.clearTimeout(timerRef.current); };
  }, [autoAdvanceMs, isPaused, index]);

  return { index, next, prev, goTo, userPaused, setUserPaused, setPolitePaused, isPaused, reducedMotion };
}

