import { useCallback, useId } from 'react';
import { useCarousel } from './useCarousel';

interface Props<T> { slides: ReadonlyArray<T>; renderSlide: (item: T, index: number) => React.ReactNode; label: string; autoAdvanceMs?: number; }

export function Carousel<T>({ slides, renderSlide, label, autoAdvanceMs = 5000 }: Props<T>) {
  const c = useCarousel({ count: slides.length, autoAdvanceMs });
  const baseId = useId();
  const onKey = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'ArrowLeft') { e.preventDefault(); c.prev(); }
    else if (e.key === 'ArrowRight') { e.preventDefault(); c.next(); }
    else if (e.key === 'Home') { e.preventDefault(); c.goTo(0); }
    else if (e.key === 'End') { e.preventDefault(); c.goTo(slides.length - 1); }
  }, [c, slides.length]);

  return (
    <section role="region" aria-roledescription="carousel" aria-label={label}
      onMouseEnter={() => c.setPolitePaused(true)} onMouseLeave={() => c.setPolitePaused(false)}
      onFocus={() => c.setPolitePaused(true)} onBlur={() => c.setPolitePaused(false)}
      onKeyDown={onKey}
      className="relative overflow-hidden bg-[oklch(0.18_0.005_250)]">
      <div className="flex transition-transform" style={{ transform: `translateX(-${c.index * 100}%)`, transitionDuration: c.reducedMotion ? '0ms' : '400ms', transitionTimingFunction: 'cubic-bezier(0.22, 1, 0.36, 1)' }}>
        {slides.map((s, i) => (
          <div key={i} id={`${baseId}-slide-${i}`} role="group" aria-roledescription="slide" aria-label={`Slide ${i + 1} of ${slides.length}`} aria-hidden={i !== c.index} className="w-full shrink-0" {...(i !== c.index ? { inert: '' as never } : {})}>{renderSlide(s, i)}</div>
        ))}
      </div>
      <button type="button" onClick={c.prev} aria-label="Previous slide" className="absolute left-2 top-1/2 -translate-y-1/2 w-12 h-12 rounded-full bg-[oklch(0.18_0.005_250_/_0.7)] text-white flex items-center justify-center focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[oklch(0.55_0.18_250)]">\u2039</button>
      <button type="button" onClick={c.next} aria-label="Next slide" className="absolute right-2 top-1/2 -translate-y-1/2 w-12 h-12 rounded-full bg-[oklch(0.18_0.005_250_/_0.7)] text-white flex items-center justify-center focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[oklch(0.55_0.18_250)]">\u203A</button>
      <div role="tablist" aria-label="Slide selector" className="absolute bottom-4 left-1/2 -translate-x-1/2 flex gap-2">
        {slides.map((_, i) => (
          <button key={i} role="tab" aria-selected={i === c.index} aria-controls={`${baseId}-slide-${i}`} aria-label={`Go to slide ${i + 1}`} onClick={() => c.goTo(i)}
            className="w-2.5 h-2.5 rounded-full focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[oklch(0.55_0.18_250)]"
            style={{ background: i === c.index ? 'oklch(0.99 0.005 250)' : 'oklch(0.99 0.005 250 / 0.4)' }} />
        ))}
      </div>
      {autoAdvanceMs && (
        <button type="button" onClick={() => c.setUserPaused(p => !p)} aria-label={c.userPaused ? 'Resume auto-advance' : 'Pause auto-advance'}
          className="absolute top-4 right-4 w-9 h-9 rounded-full bg-[oklch(0.18_0.005_250_/_0.7)] text-white text-[14px] flex items-center justify-center focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[oklch(0.55_0.18_250)]">
          {c.userPaused ? '\u25B6' : '\u2225'}
        </button>
      )}
    </section>
  );
}

export class LRU<K, V> {
  private map = new Map<K, { value: V; ts: number }>();
  constructor(private maxSize: number, private maxAgeMs: number) {}
  get(key: K): V | undefined {
    const entry = this.map.get(key);
    if (!entry) return undefined;
    if (Date.now() - entry.ts > this.maxAgeMs) { this.map.delete(key); return undefined; }
    this.map.delete(key); this.map.set(key, entry); // move to end
    return entry.value;
  }
  set(key: K, value: V): void {
    if (this.map.size >= this.maxSize) {
      const first = this.map.keys().next().value;
      if (first !== undefined) this.map.delete(first);
    }
    this.map.set(key, { value, ts: Date.now() });
  }
  isStale(key: K, freshMs: number): boolean {
    const entry = this.map.get(key);
    if (!entry) return false;
    return Date.now() - entry.ts > freshMs;
  }
}

// useLayeredSearch.ts
import { useEffect, useRef, useState } from 'react';
import { LRU } from './lru';

export interface SearchHit { id: string; title: string; path: string; excerpt: string; }
export type Source = 'cache' | 'local' | 'server';

export function useLayeredSearch(query: string, opts: { localSearch: (q: string) => ReadonlyArray<SearchHit>; serverSearch: (q: string, signal: AbortSignal) => Promise<ReadonlyArray<SearchHit>> }) {
  const cacheRef = useRef(new LRU<string, ReadonlyArray<SearchHit>>(50, 5 * 60_000));
  const [results, setResults] = useState<ReadonlyArray<SearchHit>>([]);
  const [source, setSource] = useState<Source>('cache');
  const [lastNonEmpty, setLastNonEmpty] = useState<ReadonlyArray<SearchHit>>([]);
  const debounceRef = useRef<number | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  useEffect(() => {
    const norm = query.trim().toLowerCase();
    if (!norm) { setResults([]); return; }
    const cached = cacheRef.current.get(norm);
    if (cached) {
      setResults(cached); setSource('cache');
      if (cached.length > 0) setLastNonEmpty(cached);
      if (!cacheRef.current.isStale(norm, 30_000)) return;
    } else {
      const local = opts.localSearch(norm);
      setResults(local); setSource('local');
      if (local.length > 0) setLastNonEmpty(local);
    }
    if (debounceRef.current) window.clearTimeout(debounceRef.current);
    if (abortRef.current) abortRef.current.abort();
    debounceRef.current = window.setTimeout(async () => {
      abortRef.current = new AbortController();
      try {
        const serverHits = await opts.serverSearch(norm, abortRef.current.signal);
        cacheRef.current.set(norm, serverHits);
        setResults(serverHits); setSource('server');
        if (serverHits.length > 0) setLastNonEmpty(serverHits);
      } catch (e) {
        if ((e as Error).name !== 'AbortError') console.warn(e);
      }
    }, 150);
    return () => { if (debounceRef.current) window.clearTimeout(debounceRef.current); if (abortRef.current) abortRef.current.abort(); };
  }, [query]);

  return { results, source, lastNonEmpty };
}

// usePredictivePrefetch.ts
import { useEffect } from 'react';
export function usePredictivePrefetch(url: string | null) {
  useEffect(() => {
    if (!url) return;
    const link = document.createElement('link');
    link.rel = 'prefetch';
    link.href = url;
    document.head.appendChild(link);
    return () => { try { document.head.removeChild(link); } catch {} };
  }, [url]);
}

