import { useState } from 'react';
import { useLayeredSearch, type SearchHit } from './useLayeredSearch';
import { usePredictivePrefetch } from './usePredictivePrefetch';

interface Props { localSearch: (q: string) => ReadonlyArray<SearchHit>; serverSearch: (q: string, signal: AbortSignal) => Promise<ReadonlyArray<SearchHit>>; onSelect: (hit: SearchHit) => void; }

export function DocsSearch({ localSearch, serverSearch, onSelect }: Props) {
  const [query, setQuery] = useState('');
  const [focusIdx, setFocusIdx] = useState(0);
  const { results, source, lastNonEmpty } = useLayeredSearch(query, { localSearch, serverSearch });
  usePredictivePrefetch(results[0]?.path ?? null);
  const showStale = query && results.length === 0 && lastNonEmpty.length > 0;
  const display = showStale ? lastNonEmpty : results;

  return (
    <div className="w-[480px] bg-white rounded-lg shadow-lg overflow-hidden">
      <input value={query} onChange={(e) => { setQuery(e.target.value); setFocusIdx(0); }}
        onKeyDown={(e) => {
          if (e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx(i => Math.min(display.length - 1, i + 1)); }
          else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); }
          else if (e.key === 'Enter') { e.preventDefault(); const h = display[focusIdx]; if (h) onSelect(h); }
        }}
        placeholder="Search docs\u2026" aria-label="Search documentation" aria-controls="search-results" aria-activedescendant={display[focusIdx] ? `hit-${display[focusIdx].id}` : undefined}
        className="w-full h-11 px-4 outline-none border-b border-[oklch(0.93_0.005_250)] text-[15px]" />
      {showStale && <div className="px-4 py-2 text-[12px] text-[oklch(0.55_0.005_250)] bg-[oklch(0.97_0.005_250)]">No matches for \u201C{query}\u201D \u00B7 showing previous results</div>}
      <ul id="search-results" role="listbox" className="max-h-[480px] overflow-y-auto transition-opacity duration-[200ms]" style={{ opacity: source === 'server' || source === 'cache' ? 1 : 1 }}>
        {display.map((hit, i) => (
          <li key={hit.id} id={`hit-${hit.id}`} role="option" aria-selected={i === focusIdx}
            onMouseEnter={() => setFocusIdx(i)} onClick={() => onSelect(hit)}
            className={`px-4 py-2 cursor-pointer ${i === focusIdx ? 'bg-[oklch(0.94_0.04_250)]' : 'hover:bg-[oklch(0.97_0.005_250)]'}`}
            style={{ borderBottom: source === 'local' ? '1px dotted oklch(0.55 0.005 250)' : 'none' }}>
            <div className="text-[14px] font-medium">{hit.title}</div>
            <div className="text-[12px] text-[oklch(0.55_0.005_250)] truncate">{hit.path}</div>
