import { useCallback, useRef, useState } from 'react';
export function useDragKnob(opts: { value: number; min: number; max: number; defaultValue: number; sensitivity?: number; onChange: (v: number) => void }) {
  const { value, min, max, defaultValue, sensitivity = 100, onChange } = opts;
  const dragRef = useRef<{ startY: number; startValue: number; fine: boolean } | null>(null);
  const range = max - min;
  const onPointerDown = useCallback((e: React.PointerEvent) => {
    (e.target as Element).setPointerCapture(e.pointerId);
    dragRef.current = { startY: e.clientY, startValue: value, fine: e.shiftKey };
  }, [value]);
  const onPointerMove = useCallback((e: React.PointerEvent) => {
    if (!dragRef.current) return;
    const dy = dragRef.current.startY - e.clientY; // up positive
    const fineMultiplier = dragRef.current.fine ? 0.1 : 1;
    const valueDelta = (dy / sensitivity) * range * fineMultiplier;
    onChange(Math.max(min, Math.min(max, dragRef.current.startValue + valueDelta)));
  }, [min, max, range, sensitivity, onChange]);
  const onPointerUp = useCallback(() => { dragRef.current = null; }, []);
  const onDoubleClick = useCallback(() => onChange(defaultValue), [defaultValue, onChange]);
  return { onPointerDown, onPointerMove, onPointerUp, onDoubleClick };
}

