// LevelMeter.tsx
import { useEffect, useRef, useState } from 'react';
export function LevelMeter({ level, peakHoldMs = 1500 }: { level: number; peakHoldMs?: number }) {
  const LEDS = 24;
  const [peak, setPeak] = useState(0);
  const peakTsRef = useRef(0);
  useEffect(() => {
    if (level > peak) { setPeak(level); peakTsRef.current = performance.now(); }
    else {
      const elapsed = performance.now() - peakTsRef.current;
      if (elapsed > peakHoldMs) setPeak(p => Math.max(0, p - 0.02));
    }
  }, [level, peak, peakHoldMs]);
  return (
    <div className="flex gap-1" aria-label={`Audio level ${(level * 100).toFixed(0)}%`}>
      {Array.from({ length: LEDS }).map((_, i) => {
        const threshold = i / LEDS;
        const lit = level >= threshold;
        const isPeak = Math.floor(peak * LEDS) === i;
        const color = threshold < 0.6 ? 'oklch(0.65 0.16 145)' : threshold < 0.85 ? 'oklch(0.78 0.16 80)' : 'oklch(0.6 0.18 25)';
        return <div key={i} className="w-1 h-6 rounded-sm" style={{ background: color, opacity: lit || isPeak ? 1 : 0.15 }} />;
      })}
    </div>
  );
}

