export interface Metric { id: string; label: string; value: number; format: (v: number) => string; previousValue: number; trend: ReadonlyArray<number>; direction: 'up-is-good' | 'down-is-good'; }

// useDigitRoll.ts — per-digit animation
import { useEffect, useState } from 'react';
export function useDigitRoll(value: string): { digits: ReadonlyArray<string>; key: number } {
  const [key, setKey] = useState(0);
  useEffect(() => { setKey(k => k + 1); }, [value]);
  return { digits: value.split(''), key };
}

// Sparkline.tsx
export function Sparkline({ points, width = 120, height = 32, color = 'oklch(0.55 0.005 250)', endColor = 'oklch(0.55 0.18 250)' }: { points: ReadonlyArray<number>; width?: number; height?: number; color?: string; endColor?: string }) {
  if (points.length < 2) return null;
  const min = Math.min(...points);
  const max = Math.max(...points);
  const range = max - min || 1;
  const stepX = width / (points.length - 1);
  const d = points.map((p, i) => `${i ? 'L' : 'M'}${(i * stepX).toFixed(1)} ${(height - ((p - min) / range) * height).toFixed(1)}`).join(' ');
  const lastX = (points.length - 1) * stepX;
  const lastY = height - ((points[points.length - 1] - min) / range) * height;
  return (
    <svg width={width} height={height} className="shrink-0">
      <path d={d} stroke={color} strokeWidth="1.25" fill="none" />
      <circle cx={lastX} cy={lastY} r={3} fill={endColor} />
    </svg>
  );
}

