export type BlockKind = 'p' | 'h1' | 'h2' | 'h3' | 'ul' | 'ol' | 'quote' | 'code';
export interface Block { id: string; kind: BlockKind; content: string; }

// detectMarkdownPrefix.ts
export function detectMarkdownPrefix(text: string): { kind: BlockKind; remaining: string } | null {
  if (text.startsWith('# ')) return { kind: 'h1', remaining: text.slice(2) };
  if (text.startsWith('## ')) return { kind: 'h2', remaining: text.slice(3) };
  if (text.startsWith('### ')) return { kind: 'h3', remaining: text.slice(4) };
  if (text.startsWith('* ') || text.startsWith('- ')) return { kind: 'ul', remaining: text.slice(2) };
  if (/^1\. /.test(text)) return { kind: 'ol', remaining: text.slice(3) };
  if (text.startsWith('> ')) return { kind: 'quote', remaining: text.slice(2) };
  if (text.startsWith('``` ') || text === '```') return { kind: 'code', remaining: text === '```' ? '' : text.slice(4) };
  return null;
}

