// Editor.tsx
import { useCallback, useState } from 'react';
import type { Block, BlockKind } from './types';
import { detectMarkdownPrefix } from './detectMarkdownPrefix';
import { SlashMenu } from './SlashMenu';

const BLOCK_TAGS: Record<BlockKind, string> = { p: 'p', h1: 'h1', h2: 'h2', h3: 'h3', ul: 'li', ol: 'li', quote: 'blockquote', code: 'pre' };

export function Editor({ initialBlocks }: { initialBlocks: ReadonlyArray<Block> }) {
  const [blocks, setBlocks] = useState<ReadonlyArray<Block>>(initialBlocks);
  const [slashState, setSlashState] = useState<{ blockId: string; query: string; focusedIdx: number; rect: DOMRect } | null>(null);

  const updateBlock = useCallback((id: string, content: string) => {
    setBlocks(bs => bs.map(b => b.id === id ? { ...b, content } : b));
    // markdown prefix transformation
    const md = detectMarkdownPrefix(content);
    if (md) setBlocks(bs => bs.map(b => b.id === id ? { ...b, kind: md.kind, content: md.remaining } : b));
  }, []);

  const moveBlock = useCallback((id: string, dir: 'up' | 'down') => {
    setBlocks(bs => {
      const idx = bs.findIndex(b => b.id === id);
      const next = dir === 'up' ? idx - 1 : idx + 1;
      if (idx < 0 || next < 0 || next >= bs.length) return bs;
      const copy = bs.slice();
      [copy[idx], copy[next]] = [copy[next], copy[idx]];
      return copy;
    });
  }, []);

  return (
    <div className="max-w-[720px] mx-auto px-4 py-8">
      {blocks.map(b => (
        <div key={b.id} className="group relative my-1">
          <button type="button" aria-label="Block options" tabIndex={-1} className="absolute -left-6 top-1 opacity-0 group-focus-within:opacity-60 hover:opacity-100 text-[oklch(0.55_0.005_250)] cursor-grab">\u2807</button>
          <BlockRenderer block={b} onChange={(content) => updateBlock(b.id, content)} onMove={(dir) => moveBlock(b.id, dir)} onSlashOpen={(rect, query) => setSlashState({ blockId: b.id, query, focusedIdx: 0, rect })} />
        </div>
      ))}
      {slashState && (
        <SlashMenu query={slashState.query} focusedIdx={slashState.focusedIdx} onPick={(kind) => { setBlocks(bs => bs.map(b => b.id === slashState.blockId ? { ...b, kind, content: '' } : b)); setSlashState(null); }} anchorTop={slashState.rect.bottom + window.scrollY + 4} anchorLeft={slashState.rect.left + window.scrollX} />
      )}
    </div>
  );
}

function BlockRenderer({ block, onChange, onMove, onSlashOpen }: { block: Block; onChange: (c: string) => void; onMove: (dir: 'up' | 'down') => void; onSlashOpen: (rect: DOMRect, query: string) => void }) {
  const Tag = BLOCK_TAGS[block.kind] as React.ElementType;
  const onKey = (e: React.KeyboardEvent<HTMLElement>) => {
    if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'ArrowUp') { e.preventDefault(); onMove('up'); }
    else if ((e.metaKey || e.ctrlKey) && e.shiftKey && e.key === 'ArrowDown') { e.preventDefault(); onMove('down'); }
    else if (e.key === '/' && block.content === '') { const rect = (e.target as HTMLElement).getBoundingClientRect(); onSlashOpen(rect, ''); }
  };
  return (
    <Tag contentEditable suppressContentEditableWarning onInput={(e: React.FormEvent<HTMLElement>) => onChange((e.target as HTMLElement).innerText)} onKeyDown={onKey}
      className={`outline-none ${block.kind === 'h1' ? 'text-[30px] font-medium mt-6' : block.kind === 'h2' ? 'text-[24px] font-medium mt-5' : block.kind === 'h3' ? 'text-[18px] font-medium mt-4' : block.kind === 'code' ? 'font-mono text-[14px] bg-[oklch(0.96_0.005_250)] p-3 rounded' : 'text-[16px] leading-[26px]'}`}>{block.content}</Tag>
  );
}

import { useRef } from 'react';
export interface Point { x: number; y: number; pressure?: number; }
export function useStrokeSmoother() {
  const points = useRef<Point[]>([]);
  const reset = () => { points.current = []; };
  const add = (p: Point) => { points.current.push(p); };
  const path = (): string => {
    const pts = points.current;
    if (pts.length < 2) return '';
    let d = `M${pts[0].x} ${pts[0].y}`;
    for (let i = 1; i < pts.length - 2; i++) {
      const p0 = pts[i - 1] || pts[i];
      const p1 = pts[i];
      const p2 = pts[i + 1];
      const p3 = pts[i + 2] || p2;
      const cp1x = p1.x + (p2.x - p0.x) / 6;
      const cp1y = p1.y + (p2.y - p0.y) / 6;
      const cp2x = p2.x - (p3.x - p1.x) / 6;
      const cp2y = p2.y - (p3.y - p1.y) / 6;
      d += ` C${cp1x.toFixed(1)} ${cp1y.toFixed(1)}, ${cp2x.toFixed(1)} ${cp2y.toFixed(1)}, ${p2.x.toFixed(1)} ${p2.y.toFixed(1)}`;
    }
    return d;
  };
  return { points, add, reset, path };
}

// useStrokeBroadcast.ts
import { useEffect, useRef } from 'react';
export function useStrokeBroadcast(broadcast: (points: ReadonlyArray<Point>) => void, intervalMs = 33) {
  const pendingRef = useRef<Point[]>([]);
  const timerRef = useRef<number | null>(null);
  const start = () => {
    if (timerRef.current) return;
    timerRef.current = window.setInterval(() => {
      if (pendingRef.current.length === 0) return;
      broadcast(pendingRef.current.slice());
      pendingRef.current = [];
    }, intervalMs);
  };
  const append = (p: Point) => pendingRef.current.push(p);
  const stop = () => { if (timerRef.current) { window.clearInterval(timerRef.current); timerRef.current = null; } };
  useEffect(() => () => stop(), []);
  return { start, append, stop };
}
import type { Point } from './useStrokeSmoother';

// Whiteboard.tsx (canvas layers)
import { useCallback, useRef, useState } from 'react';
import { useStrokeSmoother } from './useStrokeSmoother';
import { useStrokeBroadcast } from './useStrokeBroadcast';

export function Whiteboard({ userColor, onCommitStroke }: { userColor: string; onCommitStroke: (path: string) => void }) {
  const smoother = useStrokeSmoother();
  const localCanvasRef = useRef<HTMLCanvasElement | null>(null);
  const drawingRef = useRef(false);
  const broadcast = useStrokeBroadcast((pts) => { /* send to peers */ });

  const onPointerDown = useCallback((e: React.PointerEvent) => {
    drawingRef.current = true;
    smoother.reset();
    smoother.add({ x: e.clientX, y: e.clientY, pressure: e.pressure });
    broadcast.start();
    (e.target as Element).setPointerCapture(e.pointerId);
  }, []);

  const onPointerMove = useCallback((e: React.PointerEvent) => {
    if (!drawingRef.current) return;
    smoother.add({ x: e.clientX, y: e.clientY, pressure: e.pressure });
    broadcast.append({ x: e.clientX, y: e.clientY, pressure: e.pressure });
    const canvas = localCanvasRef.current; if (!canvas) return;
    const ctx = canvas.getContext('2d'); if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    ctx.strokeStyle = userColor;
    ctx.lineWidth = 2 * (e.pressure || 0.5) + 1;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    const path2d = new Path2D(smoother.path());
    ctx.stroke(path2d);
  }, [userColor]);

  const onPointerUp = useCallback(() => {
    if (!drawingRef.current) return;
    drawingRef.current = false;
    broadcast.stop();
    const finalPath = smoother.path();
    onCommitStroke(finalPath);
    const canvas = localCanvasRef.current; if (canvas) { const ctx = canvas.getContext('2d'); ctx?.clearRect(0, 0, canvas.width, canvas.height); }
  }, [onCommitStroke]);

  return (
    <canvas ref={localCanvasRef} width={2000} height={1400} className="absolute inset-0 cursor-crosshair touch-none"
      onPointerDown={onPointerDown} onPointerMove={onPointerMove} onPointerUp={onPointerUp} onPointerCancel={onPointerUp} aria-label="Whiteboard drawing canvas" />
  );
}

export interface ChunkState { index: number; bytes: number; status: 'pending' | 'uploading' | 'done' | 'failed'; attempts: number; }
export interface UploadState { id: string; file: File; chunks: ReadonlyArray<ChunkState>; paused: boolean; startedAt: number; bytesUploaded: number; }

// useChunkedUpload.ts
import { useCallback, useEffect, useRef, useState } from 'react';
const CHUNK_SIZE = 5 * 1024 * 1024;
const MAX_RETRY = 3;

export function useChunkedUpload(file: File, opts: { uploadChunk: (file: File, offset: number, size: number) => Promise<void> }) {
  const totalChunks = Math.ceil(file.size / CHUNK_SIZE);
  const [chunks, setChunks] = useState<ReadonlyArray<ChunkState>>(() => Array.from({ length: totalChunks }, (_, i) => ({ index: i, bytes: i === totalChunks - 1 ? file.size - i * CHUNK_SIZE : CHUNK_SIZE, status: 'pending' as const, attempts: 0 })));
  const [paused, setPaused] = useState(false);
  const startedAt = useRef(Date.now());
  const recentSpeeds = useRef<number[]>([]);

  const uploadChunk = useCallback(async (chunkIdx: number) => {
    setChunks(cs => cs.map((c, i) => i === chunkIdx ? { ...c, status: 'uploading' as const, attempts: c.attempts + 1 } : c));
    const offset = chunkIdx * CHUNK_SIZE;
    const size = Math.min(CHUNK_SIZE, file.size - offset);
    try {
      const tStart = performance.now();
      await opts.uploadChunk(file, offset, size);
      const tElapsed = performance.now() - tStart;
      recentSpeeds.current = [...recentSpeeds.current.slice(-4), size / (tElapsed / 1000)];
      setChunks(cs => cs.map((c, i) => i === chunkIdx ? { ...c, status: 'done' as const } : c));
    } catch (e) {
      setChunks(cs => cs.map((c, i) => i === chunkIdx ? { ...c, status: c.attempts >= MAX_RETRY ? 'failed' as const : 'pending' as const } : c));
    }
  }, [file, opts]);

  useEffect(() => {
    if (paused) return;
    const nextPending = chunks.findIndex(c => c.status === 'pending' && c.attempts < MAX_RETRY);
    if (nextPending === -1) return;
    const delay = chunks[nextPending].attempts > 0 ? Math.pow(2, chunks[nextPending].attempts - 1) * 1000 : 0;
    const t = window.setTimeout(() => uploadChunk(nextPending), delay);
    return () => window.clearTimeout(t);
  }, [chunks, paused, uploadChunk]);

  const bytesUploaded = chunks.reduce((sum, c) => c.status === 'done' ? sum + c.bytes : sum, 0);
  const bytesPerSec = recentSpeeds.current.length > 0 ? recentSpeeds.current.reduce((a, b) => a + b, 0) / recentSpeeds.current.length : 0;
  const bytesRemaining = file.size - bytesUploaded;
  const secondsRemaining = bytesPerSec > 0 ? Math.ceil(bytesRemaining / bytesPerSec) : null;

  return { chunks, paused, setPaused, bytesUploaded, secondsRemaining, retryChunk: uploadChunk };
}

