export function UploadRow({ name, size, chunks, bytesUploaded, secondsRemaining, paused, onPauseToggle, onCancel, onRetry }: { name: string; size: number; chunks: ReadonlyArray<ChunkState>; bytesUploaded: number; secondsRemaining: number | null; paused: boolean; onPauseToggle: () => void; onCancel: () => void; onRetry: (i: number) => void }) {
