          <div className="text-[11px] text-white/60 tabular-nums">{pct.toFixed(0)}% \u00B7 {secondsRemaining != null ? `${secondsRemaining}s remaining` : (paused ? 'paused' : '\u2026')}</div>
        </div>
        <div className="flex gap-2">
          <button type="button" onClick={onPauseToggle} className="text-[12px] text-white/70 hover:text-white">{paused ? 'Resume' : 'Pause'}</button>
          <button type="button" onClick={onCancel} aria-label="Cancel upload" className="text-[12px] text-white/70 hover:text-white">\u2715</button>
        </div>
      </header>
      <div className="mt-2 flex gap-0.5" role="progressbar" aria-valuenow={pct} aria-valuemin={0} aria-valuemax={100}>
        {chunks.map((c, i) => (
          <div key={i} className="h-1 flex-1 rounded-sm relative" style={{ background: c.status === 'done' ? 'oklch(0.55 0.14 145)' : c.status === 'uploading' ? 'oklch(0.55 0.18 250)' : c.status === 'failed' ? 'oklch(0.6 0.18 25)' : 'oklch(0.4 0.005 250)', animation: c.status === 'uploading' ? 'chunkShimmer 1500ms ease-in-out infinite' : c.status === 'failed' ? 'chunkPulse 1500ms ease-in-out infinite' : undefined }}>
            {c.status === 'failed' && <button type="button" onClick={() => onRetry(i)} className="absolute inset-0" aria-label={`Retry chunk ${i + 1}`} />}
          </div>
        ))}
      </div>
      {anyFailed && <div className="mt-1 text-[11px] text-[oklch(0.7_0.16_25)]">Some chunks failed \u00B7 retrying automatically</div>}
      <style>{`@keyframes chunkShimmer { 0% { opacity: 1 } 50% { opacity: 0.6 } 100% { opacity: 1 } } @keyframes chunkPulse { 0% { opacity: 1 } 50% { opacity: 0.4 } 100% { opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='chunkShimmer'], [style*='chunkPulse'] { animation: none !important } }`}</style>
    </article>
  );
}

import { useEffect, useRef, useState } from 'react';
export function useStepObserver(stepIds: ReadonlyArray<string>) {
  const [activeStep, setActiveStep] = useState<string | null>(stepIds[0] ?? null);
  const refs = useRef<Map<string, HTMLElement>>(new Map());
  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
      const visible = entries.filter(e => e.isIntersecting).sort((a, b) => Math.abs(a.boundingClientRect.top - window.innerHeight / 2) - Math.abs(b.boundingClientRect.top - window.innerHeight / 2));
      if (visible[0]) setActiveStep((visible[0].target as HTMLElement).dataset.stepid ?? null);
    }, { rootMargin: '-50% 0px -50% 0px', threshold: 0 });
    refs.current.forEach(el => observer.observe(el));
    return () => observer.disconnect();
  }, [stepIds.join(',')]);
  const setRef = (id: string) => (el: HTMLElement | null) => { if (el) refs.current.set(id, el); else refs.current.delete(id); };
  return { activeStep, setRef };
}

