// useTourState.ts
import { useEffect, useState } from 'react';
const KEY = 'tour-completed-v1';
export function useTourState() {
  const [completed, setCompleted] = useState<Set<string>>(() => {
    try { return new Set(JSON.parse(localStorage.getItem(KEY) ?? '[]')); } catch { return new Set(); }
  });
  const markComplete = (id: string) => {
    setCompleted(prev => {
      const next = new Set(prev); next.add(id);
      try { localStorage.setItem(KEY, JSON.stringify(Array.from(next))); } catch {}
      return next;
    });
  };
  return { completed, markComplete };
}

// useUserInputOnElement.ts
import { useEffect, useRef } from 'react';
export function useUserInputOnElement(selector: string, onAction: () => void) {
  const fired = useRef(false);
  useEffect(() => {
    fired.current = false;
    const el = document.querySelector(selector) as HTMLElement | null;
    if (!el) return;
    const handler = () => {
      if (fired.current) return;
      fired.current = true;
      onAction();
    };
    el.addEventListener('pointerdown', handler);
    el.addEventListener('keydown', handler);
    return () => { el.removeEventListener('pointerdown', handler); el.removeEventListener('keydown', handler); };
  }, [selector, onAction]);
}

// AmbientTour.tsx
import { useEffect, useMemo, useState } from 'react';
import type { TourLesson } from './types';
import { useTourState } from './useTourState';
import { useUserInputOnElement } from './useUserInputOnElement';

export function AmbientTour({ lessons }: { lessons: ReadonlyArray<TourLesson> }) {
  const { completed, markComplete } = useTourState();
  const [activeLesson, setActiveLesson] = useState<TourLesson | null>(null);
  const [targetRect, setTargetRect] = useState<DOMRect | null>(null);

  const next = useMemo(() => lessons.find(l => !completed.has(l.id) && l.trigger()), [lessons, completed]);

  useEffect(() => {
    if (!next || activeLesson?.id === next.id) return;
    const el = document.querySelector(next.targetSelector) as HTMLElement | null;
    if (!el) return;
    setActiveLesson(next);
    setTargetRect(el.getBoundingClientRect());
  }, [next, activeLesson?.id]);

  useUserInputOnElement(activeLesson?.targetSelector ?? '__none__', () => {
    if (!activeLesson) return;
    markComplete(activeLesson.id);
    setActiveLesson(null);
  });

  if (!activeLesson || !targetRect) return null;
  return (
    <div aria-hidden="true" className="fixed pointer-events-none z-30" style={{ top: targetRect.top + targetRect.height / 2 - 20, left: targetRect.left + targetRect.width / 2 - 20, animation: 'tourIn 200ms ease-out' }}>
      {activeLesson.gesture}
      <style>{`@keyframes tourIn { from { opacity: 0 } to { opacity: 0.7 } } @media (prefers-reduced-motion: reduce) { [style*='tourIn'] { animation: none !important; opacity: 1 } }`}</style>
    </div>
  );
}

