export interface ColumnDef<TRow> { id: string; label: string; type: 'text' | 'number' | 'date' | 'select'; accessor: (row: TRow) => string | number; validate?: (val: unknown) => string | null; options?: ReadonlyArray<string>; }

// DataGrid.tsx
import { useCallback, useMemo, useState } from 'react';

interface Props<TRow extends { id: string }> { rows: ReadonlyArray<TRow>; columns: ReadonlyArray<ColumnDef<TRow>>; onSave: (changes: ReadonlyArray<{ rowId: string; colId: string; value: unknown }>) => Promise<{ ok: true } | { ok: false; failures: ReadonlyArray<{ rowId: string; colId: string; reason: string }> }>; }

export function DataGrid<TRow extends { id: string }>({ rows, columns, onSave }: Props<TRow>) {
  const [dirty, setDirty] = useState<Map<string, Map<string, unknown>>>(new Map());
  const [errors, setErrors] = useState<Map<string, string>>(new Map());
  const [saving, setSaving] = useState(false);

  const cellKey = (rid: string, cid: string) => `${rid}::${cid}`;
  const dirtyCount = Array.from(dirty.values()).reduce((sum, m) => sum + m.size, 0);

  const setCellValue = useCallback((rowId: string, colId: string, value: unknown) => {
    setDirty(d => {
      const next = new Map(d);
      if (!next.has(rowId)) next.set(rowId, new Map());
      next.get(rowId)!.set(colId, value);
      return next;
    });
    const col = columns.find(c => c.id === colId);
    const err = col?.validate?.(value) ?? null;
    setErrors(e => { const next = new Map(e); if (err) next.set(cellKey(rowId, colId), err); else next.delete(cellKey(rowId, colId)); return next; });
  }, [columns]);

  const discard = useCallback(() => { setDirty(new Map()); setErrors(new Map()); }, []);

  const save = useCallback(async () => {
    setSaving(true);
    const changes: Array<{ rowId: string; colId: string; value: unknown }> = [];
    dirty.forEach((cols, rid) => cols.forEach((v, cid) => changes.push({ rowId: rid, colId: cid, value: v })));
    const result = await onSave(changes);
    setSaving(false);
    if (result.ok) { setDirty(new Map()); setErrors(new Map()); }
    else {
      const newErrors = new Map(errors);
      result.failures.forEach(f => newErrors.set(cellKey(f.rowId, f.colId), f.reason));
      setErrors(newErrors);
    }
  }, [dirty, errors, onSave]);

  return (
    <div className="relative">
      <table className="w-full border-collapse text-[13px]">
        <thead>
          <tr>{columns.map(c => <th key={c.id} className="text-left text-[11px] uppercase tracking-wider font-semibold px-3 py-2 text-[oklch(0.55_0.005_250)] border-b border-[oklch(0.92_0.005_250)]">{c.label}</th>)}</tr>
        </thead>
        <tbody>
          {rows.map(row => (
            <tr key={row.id}>
              {columns.map(col => {
                const k = cellKey(row.id, col.id);
                const isDirty = dirty.get(row.id)?.has(col.id);
                const error = errors.get(k);
                const currentValue = isDirty ? dirty.get(row.id)!.get(col.id) : col.accessor(row);
                return (
                  <td key={col.id} className="px-3 py-1 border-b border-[oklch(0.95_0.005_250)] relative" style={{ borderLeft: error ? '2px solid oklch(0.6 0.18 25)' : isDirty ? '2px solid oklch(0.55 0.18 250)' : '2px solid transparent', transition: 'border-color 300ms ease-out' }}>
                    <input value={String(currentValue ?? '')} onChange={(e) => setCellValue(row.id, col.id, col.type === 'number' ? Number(e.target.value) : e.target.value)}
                      onKeyDown={(e) => { if (e.key === 'Escape') { e.preventDefault(); setDirty(d => { const next = new Map(d); next.get(row.id)?.delete(col.id); return next; }); } }}
                      className="w-full bg-transparent outline-none" />
                    {error && <div className="absolute top-full left-0 z-10 text-[11px] text-[oklch(0.55_0.16_25)] bg-white px-1 py-0.5 rounded shadow" role="alert">{error}</div>}
                  </td>
                );
              })}
            </tr>
          ))}
        </tbody>
      </table>
      {dirtyCount > 0 && (
        <div className="fixed bottom-0 left-0 right-0 h-12 bg-[oklch(0.18_0.005_250)] text-white flex items-center justify-center gap-4 text-[13px]" style={{ animation: 'barIn 200ms ease-out' }} role="status" aria-live="polite">
          <span>{dirtyCount} unsaved {dirtyCount === 1 ? 'change' : 'changes'}</span>
          <button type="button" onClick={discard} className="px-3 py-1 rounded border border-white/20 hover:border-white/40">Discard</button>
          <button type="button" onClick={save} disabled={saving || errors.size > 0} className="px-3 py-1 rounded bg-[oklch(0.55_0.18_250)] hover:bg-[oklch(0.45_0.18_250)] disabled:opacity-50">{saving ? 'Saving\u2026' : 'Save'}</button>
          <style>{`@keyframes barIn { from { transform: translateY(100%) } to { transform: translateY(0) } } @media (prefers-reduced-motion: reduce) { [style*='barIn'] { animation: none !important } }`}</style>
        </div>
      )}
    </div>
  );
}

