// useOrbitCamera.ts
import { useFrame, useThree } from '@react-three/fiber';
import { useEffect, useRef } from 'react';
import { Spherical, Vector3 } from 'three';

export function useOrbitCamera({ targetCard, defaultRadius = 6, focusRadius = 3 }: { targetCard: [number, number, number] | null; defaultRadius?: number; focusRadius?: number }) {
  const { camera } = useThree();
  const sph = useRef(new Spherical(defaultRadius, Math.PI / 2, 0));
  const target = useRef(new Vector3(0, 0, 0));
  const dragging = useRef(false);
  const lastPointer = useRef<{ x: number; y: number } | null>(null);

  useEffect(() => {
    const onDown = (e: PointerEvent) => { dragging.current = true; lastPointer.current = { x: e.clientX, y: e.clientY }; };
    const onMove = (e: PointerEvent) => {
      if (!dragging.current || !lastPointer.current) return;
      const dx = e.clientX - lastPointer.current.x;
      const dy = e.clientY - lastPointer.current.y;
      sph.current.theta -= dx * 0.005;
      sph.current.phi = Math.max(0.3, Math.min(Math.PI - 0.3, sph.current.phi - dy * 0.005));
      lastPointer.current = { x: e.clientX, y: e.clientY };
    };
    const onUp = () => { dragging.current = false; lastPointer.current = null; };
    window.addEventListener('pointerdown', onDown);
    window.addEventListener('pointermove', onMove);
    window.addEventListener('pointerup', onUp);
    return () => {
      window.removeEventListener('pointerdown', onDown);
      window.removeEventListener('pointermove', onMove);
      window.removeEventListener('pointerup', onUp);
    };
  }, []);

  useFrame(() => {
    const desiredRadius = targetCard ? focusRadius : defaultRadius;
    sph.current.radius += (desiredRadius - sph.current.radius) * 0.08;
    if (targetCard) {
      target.current.lerp(new Vector3(...targetCard), 0.08);
    } else {
      target.current.lerp(new Vector3(0, 0, 0), 0.08);
    }
    const pos = new Vector3().setFromSpherical(sph.current).add(target.current);
    camera.position.copy(pos);
    camera.lookAt(target.current);
  });
  return sph.current;
}

