// useBottomSheet.ts
import { useCallback, useRef, useState } from 'react';
export function useBottomSheet(snapPoints: ReadonlyArray<number>, initial = 0) {
  const [snapIdx, setSnapIdx] = useState(initial);
  const [dragOffset, setDragOffset] = useState(0);
  const dragStart = useRef<{ y: number; baseHeight: number } | null>(null);
  const viewportH = typeof window !== 'undefined' ? window.innerHeight : 800;
  const currentHeight = snapPoints[snapIdx] * viewportH - dragOffset;

  const onPointerDown = (e: React.PointerEvent) => {
    dragStart.current = { y: e.clientY, baseHeight: snapPoints[snapIdx] * viewportH };
    (e.target as Element).setPointerCapture(e.pointerId);
  };
  const onPointerMove = (e: React.PointerEvent) => {
    if (!dragStart.current) return;
    setDragOffset(e.clientY - dragStart.current.y);
  };
  const onPointerUp = () => {
    if (!dragStart.current) return;
    dragStart.current = null;
    const heightPx = currentHeight;
    const nearestIdx = snapPoints.reduce((best, sp, i) => Math.abs(sp * viewportH - heightPx) < Math.abs(snapPoints[best] * viewportH - heightPx) ? i : best, 0);
    setSnapIdx(nearestIdx);
    setDragOffset(0);
  };
  const cycleSnap = useCallback(() => setSnapIdx(i => (i + 1) % snapPoints.length), [snapPoints.length]);
  return { snapIdx, currentHeight, onPointerDown, onPointerMove, onPointerUp, cycleSnap, isDragging: !!dragStart.current };
}

