import { useEffect } from 'react';
export function useEscKey(onEsc: () => void, active: boolean) {
  useEffect(() => {
    if (!active) return;
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onEsc(); };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [onEsc, active]);
}

// useScrollLock.ts
import { useEffect } from 'react';
export function useScrollLock(active: boolean) {
  useEffect(() => {
    if (!active) return;
    const scrollbarWidth = window.innerWidth - document.documentElement.clientWidth;
    document.body.style.overflow = 'hidden';
    document.body.style.paddingRight = `${scrollbarWidth}px`;
    return () => { document.body.style.overflow = ''; document.body.style.paddingRight = ''; };
  }, [active]);
}

// useInertBackground.ts
import { useEffect } from 'react';
export function useInertBackground(modalRoot: HTMLElement | null, active: boolean) {
  useEffect(() => {
    if (!active || !modalRoot) return;
    const siblings = Array.from(document.body.children).filter(c => c !== modalRoot && !modalRoot.contains(c));
    siblings.forEach(s => s.setAttribute('inert', ''));
    return () => { siblings.forEach(s => s.removeAttribute('inert')); };
  }, [modalRoot, active]);
}

// useFocusTrap.ts (from batch 01 task 22 — re-exported for completeness)
import { useEffect, useRef } from 'react';
export function useFocusTrap<T extends HTMLElement>(active: boolean) {
  const ref = useRef<T | null>(null);
  useEffect(() => {
    if (!active) return;
    const root = ref.current; if (!root) return;
    const sel = 'a[href], button:not([disabled]), input:not([disabled]), select:not([disabled]), textarea:not([disabled]), [tabindex]:not([tabindex="-1"])';
    const onKey = (e: KeyboardEvent) => {
      if (e.key !== 'Tab') return;
      const f = Array.from(root.querySelectorAll<HTMLElement>(sel));
      if (f.length === 0) { e.preventDefault(); return; }
      const first = f[0], last = f[f.length - 1];
      if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
      else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [active]);
  return ref;
}

