import { useEffect, useId, useRef } from 'react';
import { createPortal } from 'react-dom';
import { useEscKey } from './useEscKey';
import { useScrollLock } from './useScrollLock';
import { useInertBackground } from './useInertBackground';
import { useFocusTrap } from './useFocusTrap';

interface Props { open: boolean; onClose: () => void; title: string; children: React.ReactNode; closeOnBackdrop?: boolean; }

export function Modal({ open, onClose, title, children, closeOnBackdrop = true }: Props) {
  const trapRef = useFocusTrap<HTMLDivElement>(open);
  const previousFocusRef = useRef<HTMLElement | null>(null);
  const titleId = useId();
  useEscKey(onClose, open);
  useScrollLock(open);
  useInertBackground(trapRef.current, open);

  useEffect(() => {
    if (!open) return;
    previousFocusRef.current = document.activeElement as HTMLElement | null;
    const t = window.setTimeout(() => {
      const root = trapRef.current; if (!root) return;
      const autofocus = root.querySelector<HTMLElement>('[data-autofocus]');
      const first = root.querySelector<HTMLElement>('button:not([disabled]), input:not([disabled])');
      (autofocus ?? first)?.focus();
    }, 0);
    return () => {
      window.clearTimeout(t);
      const prev = previousFocusRef.current;
      if (prev && document.contains(prev)) prev.focus();
      else (document.querySelector('h1') as HTMLElement | null)?.focus();
    };
  }, [open, trapRef]);

  if (!open) return null;
  return createPortal(
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-[oklch(0.18_0.005_250/0.6)]" onClick={closeOnBackdrop ? onClose : undefined} style={{ animation: 'modalIn 150ms cubic-bezier(0, 0, 0.2, 1)' }}>
      <div ref={trapRef} onClick={(e) => e.stopPropagation()} role="dialog" aria-modal="true" aria-labelledby={titleId} className="relative bg-white rounded-xl shadow-2xl p-6 min-w-[320px] max-w-[540px] w-[80vw]">
        <h2 id={titleId} className="text-[17px] font-medium pr-8">{title}</h2>
        <button type="button" onClick={onClose} aria-label="Close dialog" className="absolute top-4 right-4 w-8 h-8 flex items-center justify-center text-[oklch(0.55_0.005_250)] hover:text-[oklch(0.2_0.01_250)] focus-visible:outline focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-[oklch(0.55_0.18_250)] rounded">
          <svg width="16" height="16" viewBox="0 0 16 16" aria-hidden="true"><path d="M4 4 L12 12 M12 4 L4 12" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" /></svg>
        </button>
        <div className="mt-4">{children}</div>
      </div>
      <style>{`@keyframes modalIn { from { opacity: 0; transform: translateY(8px) } to { opacity: 1; transform: translateY(0) } } @media (prefers-reduced-motion: reduce) { [style*='modalIn'] { animation: none !important } }`}</style>
    </div>,
    document.body
  );
}

import { useEffect, useMemo, useRef, useState } from 'react';

interface Options<TItem> { items: ReadonlyArray<TItem>; estimatedHeight: number; overscan?: number; getId: (item: TItem) => string; }

export function useVirtualScroll<TItem>({ items, estimatedHeight, overscan = 6, getId }: Options<TItem>) {
  const scrollerRef = useRef<HTMLDivElement | null>(null);
  const heightsRef = useRef<Map<string, number>>(new Map());
  const [scrollTop, setScrollTop] = useState(0);
  const [viewportH, setViewportH] = useState(800);

  const offsets = useMemo(() => {
    const out: number[] = [0];
    let sum = 0;
    for (const item of items) {
      sum += heightsRef.current.get(getId(item)) ?? estimatedHeight;
      out.push(sum);
    }
    return out;
  }, [items, estimatedHeight, getId]);

  const totalHeight = offsets[offsets.length - 1] ?? 0;

  const { start, end } = useMemo(() => {
    let s = 0;
    while (s < items.length && offsets[s + 1] < scrollTop) s++;
    let e = s;
    while (e < items.length && offsets[e] < scrollTop + viewportH) e++;
    return { start: Math.max(0, s - overscan), end: Math.min(items.length, e + overscan) };
  }, [items.length, offsets, scrollTop, viewportH, overscan]);

  const measureItem = (id: string, h: number) => {
    if (heightsRef.current.get(id) === h) return;
    heightsRef.current.set(id, h);
  };

  useEffect(() => {
    const el = scrollerRef.current; if (!el) return;
    setViewportH(el.clientHeight);
    const onScroll = () => setScrollTop(el.scrollTop);
    el.addEventListener('scroll', onScroll, { passive: true });
    const ro = new ResizeObserver(() => setViewportH(el.clientHeight));
    ro.observe(el);
    return () => { el.removeEventListener('scroll', onScroll); ro.disconnect(); };
  }, []);

  const visible = items.slice(start, end);
  const offsetTop = offsets[start];
  return { scrollerRef, visible, totalHeight, offsetTop, measureItem, scrollTop };
}

// useScrollRestoration.ts
import { useEffect, useRef } from 'react';
export function useScrollRestoration(key: string, scrollerRef: React.RefObject<HTMLDivElement | null>) {
  const saved = useRef(false);
  useEffect(() => {
    const el = scrollerRef.current; if (!el) return;
    const raw = sessionStorage.getItem(`scroll:${key}`);
    if (raw) {
      const top = parseInt(raw, 10);
      requestAnimationFrame(() => { el.scrollTop = top; });
    }
    return () => { if (el) sessionStorage.setItem(`scroll:${key}`, String(el.scrollTop)); };
  }, [key, scrollerRef]);
}

// VirtualFeed.tsx
import { useCallback, useEffect, useRef } from 'react';
import { useVirtualScroll } from './useVirtualScroll';
import { useScrollRestoration } from './useScrollRestoration';

interface BaseItem { id: string; }
interface Props<TItem extends BaseItem> { items: ReadonlyArray<TItem>; renderItem: (item: TItem) => React.ReactNode; skeletonHeight: number; onLoadMore: () => void; routeKey: string; hasMore: boolean; }

export function VirtualFeed<TItem extends BaseItem>({ items, renderItem, skeletonHeight, onLoadMore, routeKey, hasMore }: Props<TItem>) {
  const v = useVirtualScroll({ items, estimatedHeight: skeletonHeight, getId: (i) => i.id });
  useScrollRestoration(routeKey, v.scrollerRef);
  const sentinelRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    const el = sentinelRef.current; if (!el || !hasMore) return;
    const obs = new IntersectionObserver((entries) => { if (entries.some(e => e.isIntersecting)) onLoadMore(); }, { rootMargin: '150% 0px 150% 0px' });
    obs.observe(el);
    return () => obs.disconnect();
  }, [onLoadMore, hasMore]);

  return (
    <div ref={v.scrollerRef} className="h-full overflow-y-auto">
      <div style={{ height: v.totalHeight, position: 'relative' }}>
        <div style={{ transform: `translateY(${v.offsetTop}px)` }}>
          {v.visible.map((item) => <MeasuredItem key={item.id} item={item} renderItem={renderItem} onMeasure={v.measureItem} />)}
        </div>
        <div ref={sentinelRef} className="absolute bottom-0 left-0 w-full h-px" />
      </div>
    </div>
  );
}

function MeasuredItem<TItem extends BaseItem>({ item, renderItem, onMeasure }: { item: TItem; renderItem: (i: TItem) => React.ReactNode; onMeasure: (id: string, h: number) => void }) {
  const ref = useRef<HTMLDivElement | null>(null);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const ro = new ResizeObserver(([entry]) => onMeasure(item.id, Math.ceil(entry.contentRect.height)));
    ro.observe(el);
    return () => ro.disconnect();
  }, [item.id, onMeasure]);
  return <div ref={ref}>{renderItem(item)}</div>;
}

