export type Token = { kind: 'text'; value: string } | { kind: 'filter'; field: string; value: string } | { kind: 'op'; op: 'AND' | 'OR' | 'NOT' };
export interface FilterSchema { field: string; valueSuggestions: (query: string) => Promise<ReadonlyArray<{ value: string; count?: number }>>; }

// parse.ts
export function tokenize(input: string): Token[] {
  const out: Token[] = [];
  const re = /"([^"]+)"|(\w+):(\"[^\"]+\"|\S+)|\bAND\b|\bOR\b|\bNOT\b|-\S+|\S+/g;
  let match;
  while ((match = re.exec(input))) {
    if (match[0] === 'AND' || match[0] === 'OR' || match[0] === 'NOT') out.push({ kind: 'op', op: match[0] });
    else if (match[0].startsWith('-')) out.push({ kind: 'op', op: 'NOT' });
    else if (match[2] && match[3]) out.push({ kind: 'filter', field: match[2], value: match[3].replace(/\"/g, '') });
    else out.push({ kind: 'text', value: match[1] || match[0] });
  }
  return out;
}

// FilterSearch.tsx
import { useEffect, useMemo, useRef, useState } from 'react';
import { tokenize, type Token } from './parse';

const FILTER_FIELDS = ['status', 'assignee', 'label', 'priority', 'project'];

export function FilterSearch({ onSearch, getSuggestions }: { onSearch: (tokens: Token[]) => void; getSuggestions: (field: string, prefix: string) => Promise<ReadonlyArray<{ value: string; count?: number }>> }) {
  const [input, setInput] = useState('');
  const [tokens, setTokens] = useState<Token[]>([]);
  const [suggestions, setSuggestions] = useState<ReadonlyArray<{ display: string; value: string; count?: number; kind: 'field' | 'value' | 'recent' }>>([]);
  const [focusIdx, setFocusIdx] = useState(0);
  const inputRef = useRef<HTMLInputElement | null>(null);

  // determine current token context
  const currentContext = useMemo(() => {
    const lastSpace = input.lastIndexOf(' ');
    const currentWord = lastSpace === -1 ? input : input.slice(lastSpace + 1);
    const colon = currentWord.indexOf(':');
    if (colon === -1) return { kind: 'field' as const, prefix: currentWord };
    return { kind: 'value' as const, field: currentWord.slice(0, colon), prefix: currentWord.slice(colon + 1) };
  }, [input]);

  useEffect(() => {
    let cancelled = false;
    (async () => {
      if (currentContext.kind === 'field') {
        setSuggestions(FILTER_FIELDS.filter(f => f.startsWith(currentContext.prefix)).map(f => ({ display: `${f}:`, value: `${f}:`, kind: 'field' as const })));
      } else {
        const vals = await getSuggestions(currentContext.field, currentContext.prefix);
        if (cancelled) return;
        setSuggestions(vals.map(v => ({ display: `${currentContext.field}:${v.value}`, value: `${currentContext.field}:${v.value}`, count: v.count, kind: 'value' as const })));
      }
    })();
    return () => { cancelled = true; };
  }, [currentContext, getSuggestions]);

  const commitInput = () => {
    const parsed = tokenize(input);
    setTokens(parsed);
    setInput('');
    onSearch(parsed);
  };

  const insertSuggestion = (val: string) => {
    const lastSpace = input.lastIndexOf(' ');
    setInput((lastSpace === -1 ? '' : input.slice(0, lastSpace + 1)) + val + ' ');
    inputRef.current?.focus();
  };

  const onKey = (e: React.KeyboardEvent) => {
    if (e.key === 'ArrowDown') { e.preventDefault(); setFocusIdx(i => Math.min(suggestions.length - 1, i + 1)); }
    else if (e.key === 'ArrowUp') { e.preventDefault(); setFocusIdx(i => Math.max(0, i - 1)); }
    else if (e.key === 'Tab') { e.preventDefault(); const s = suggestions[focusIdx]; if (s) insertSuggestion(s.value); }
    else if (e.key === 'Enter') { e.preventDefault(); commitInput(); }
    else if (e.key === 'Backspace' && input === '' && tokens.length > 0) { setTokens(t => t.slice(0, -1)); }
  };

  return (
    <div className="relative">
      <div className="flex items-center flex-wrap gap-1 px-2 h-10 border border-[oklch(0.85_0.005_250)] rounded-md focus-within:border-[oklch(0.55_0.18_250)]">
        {tokens.map((t, i) => (
          <span key={i} className="flex items-center text-[14px]" style={{ animation: 'pillIn 80ms ease-out' }}>
            {t.kind === 'filter' ? (
              <span className="px-2 py-0.5 rounded bg-[oklch(0.94_0.04_250)] text-[oklch(0.3_0.04_250)]"><span className="text-[12px] font-medium">{t.field}:</span>{t.value}</span>
            ) : t.kind === 'op' ? (
              <span className="px-1.5 py-0.5 rounded bg-[oklch(0.9_0.005_250)] text-[oklch(0.3_0.005_250)] text-[12px] uppercase tracking-wider">{t.op}</span>
            ) : (
              <span className="text-[14px]">{t.value}</span>
            )}
          </span>
        ))}
        <input ref={inputRef} value={input} onChange={(e) => { setInput(e.target.value); setFocusIdx(0); }} onKeyDown={onKey} className="flex-1 outline-none text-[14px] min-w-[120px]" placeholder={tokens.length === 0 ? 'Search or filter\u2026' : ''} aria-label="Search and filter" aria-controls="filter-suggestions" aria-activedescendant={suggestions[focusIdx] ? `sug-${focusIdx}` : undefined} />
      </div>
      {suggestions.length > 0 && (
        <ul id="filter-suggestions" role="listbox" className="absolute top-full left-0 right-0 mt-1 max-h-[360px] overflow-y-auto bg-white rounded-md shadow-lg border border-[oklch(0.92_0.005_250)]" style={{ animation: 'sugIn 80ms ease-out' }}>
          {suggestions.map((s, i) => (
            <li key={s.value} id={`sug-${i}`} role="option" aria-selected={i === focusIdx} onClick={() => insertSuggestion(s.value)} className={`flex items-center justify-between px-3 py-1.5 text-[13px] ${i === focusIdx ? 'bg-[oklch(0.94_0.04_250)]' : 'hover:bg-[oklch(0.97_0.005_250)]'} cursor-pointer`}>
              <span>{s.display}</span>
              {s.count != null && <span className="text-[11px] tabular-nums text-[oklch(0.55_0.005_250)]">{s.count}</span>}
            </li>
          ))}
        </ul>
      )}
      <style>{`@keyframes pillIn { from { opacity: 0; max-width: 0 } to { opacity: 1; max-width: 200px } } @keyframes sugIn { from { opacity: 0 } to { opacity: 1 } }`}</style>
    </div>
  );
}

