// Timer.tsx
import { useEffect, useState } from 'react';
export function Timer({ startedAt, targetSec }: { startedAt: number; targetSec?: number }) {
  const [elapsed, setElapsed] = useState(0);
  useEffect(() => {
    const tick = () => setElapsed(Math.floor((Date.now() - startedAt) / 1000));
    tick();
    const id = window.setInterval(tick, 250);
    return () => window.clearInterval(id);
  }, [startedAt]);
  const m = Math.floor(elapsed / 60);
  const s = elapsed % 60;
  const color = !targetSec ? 'oklch(0.85 0.005 250)' : elapsed > targetSec ? 'oklch(0.6 0.18 25)' : elapsed > targetSec * 0.9 ? 'oklch(0.75 0.16 60)' : 'oklch(0.85 0.005 250)';
  return <div className="font-mono tabular-nums text-[32px]" style={{ color }} aria-label={`Elapsed time ${m} minutes ${s} seconds`}>{String(m).padStart(2, '0')}:{String(s).padStart(2, '0')}</div>;
}

