import { useCallback, useEffect, useState } from 'react';
import type { Slide, AudienceViewer, Reaction } from './types';
import { Timer } from './Timer';

interface Props { slides: ReadonlyArray<Slide>; targetSec?: number; viewers: ReadonlyArray<AudienceViewer>; reactions: ReadonlyArray<Reaction>; onSlideChange: (index: number) => void; }

export function PresenterView({ slides, targetSec, viewers, reactions, onSlideChange }: Props) {
  const [idx, setIdx] = useState(0);
  const [startedAt] = useState(Date.now());
  const [blackout, setBlackout] = useState(false);

  const next = useCallback(() => { const n = Math.min(slides.length - 1, idx + 1); setIdx(n); onSlideChange(n); }, [idx, slides.length, onSlideChange]);
  const prev = useCallback(() => { const n = Math.max(0, idx - 1); setIdx(n); onSlideChange(n); }, [idx, onSlideChange]);

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === ' ' || e.key === 'ArrowRight') { e.preventDefault(); if (e.shiftKey) prev(); else next(); }
      else if (e.key === 'ArrowLeft') { e.preventDefault(); prev(); }
      else if (e.key === 'b' || e.key === 'B') { setBlackout(b => !b); }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [next, prev]);

  const current = slides[idx];
  const upcoming = slides[idx + 1];
  const recentReactions = reactions.filter(r => Date.now() - r.timestamp < 5000);

  return (
    <div className="min-h-screen bg-[oklch(0.10_0.005_250)] text-white p-6 grid grid-cols-[1fr_400px] gap-6">
      <div className="flex flex-col">
        <div className="flex items-center justify-between mb-4">
          <Timer startedAt={startedAt} targetSec={targetSec} />
          <span className="text-[14px] tabular-nums">{idx + 1} / {slides.length}</span>
        </div>
        <div className="flex-1 bg-white text-black rounded-lg overflow-hidden flex items-center justify-center relative" aria-label={`Current slide ${idx + 1}`}>
          {current?.content}
          {blackout && <div className="absolute inset-0 bg-black" aria-label="Audience blackout" />}
        </div>
      </div>
      <div className="flex flex-col gap-4">
        <div>
          <div className="text-[11px] uppercase tracking-wider text-[oklch(0.55_0.005_250)] mb-1">Next slide</div>
          <div className="aspect-video bg-white text-black rounded overflow-hidden flex items-center justify-center text-[10px]" style={{ animation: 'previewSlide 200ms cubic-bezier(0.22, 1, 0.36, 1)' }}>{upcoming?.content ?? 'End of deck'}</div>
        </div>
        <div className="flex-1 overflow-y-auto">
          <div className="text-[11px] uppercase tracking-wider text-[oklch(0.55_0.005_250)] mb-2">Notes</div>
          <div className="text-[17px] leading-[26px] whitespace-pre-wrap">{current?.notes ?? ''}</div>
        </div>
        <div className="flex items-center justify-between border-t border-white/10 pt-3">
          <div className="flex items-center gap-2">
            <div className="flex -space-x-1">{viewers.slice(0, 5).map(v => <span key={v.id} className="w-2 h-2 rounded-full" style={{ background: v.lagMs > 2000 ? 'oklch(0.75 0.16 80)' : 'oklch(0.55 0.14 145)' }} />)}</div>
            <span className="text-[11px] tabular-nums text-[oklch(0.65_0.005_250)]">{viewers.length} watching</span>
          </div>
          <div className="flex gap-2">
            {recentReactions.slice(0, 5).map(r => <span key={r.id} className="text-[14px]" style={{ animation: 'reactionIn 200ms ease-out' }}>{r.kind === 'heart' ? '\u2665' : r.kind === 'clap' ? '\u270B' : '\u1F44D'}</span>)}
          </div>
        </div>
        <style>{`@keyframes previewSlide { from { opacity: 0; transform: translateY(-8px) } to { opacity: 1; transform: translateY(0) } } @keyframes reactionIn { from { transform: scale(0.5); opacity: 0 } to { transform: scale(1); opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='previewSlide'], [style*='reactionIn'] { animation: none !important } }`}</style>
      </div>
    </div>
  );
}

export interface LinkPreview { title: string; snippet: string; thumbnail?: string; author?: string; updatedAt: number; }

// previewCache.ts
interface Entry { preview: LinkPreview; cachedAt: number; }
const cache = new Map<string, Entry>();
const MAX_AGE = 5 * 60_000;
export function getCachedPreview(url: string): LinkPreview | null {
  const e = cache.get(url);
  if (!e) return null;
  if (Date.now() - e.cachedAt > MAX_AGE) { cache.delete(url); return null; }
  return e.preview;
}
export function setCachedPreview(url: string, preview: LinkPreview) {
  cache.set(url, { preview, cachedAt: Date.now() });
}

// useHoverIntent.ts
import { useEffect, useRef, useState } from 'react';
export function useHoverIntent(ref: React.RefObject<HTMLElement | null>, delayMs: number) {
  const [hovering, setHovering] = useState(false);
  const [intended, setIntended] = useState(false);
  const timerRef = useRef<number | null>(null);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const onEnter = () => {
      setHovering(true);
      timerRef.current = window.setTimeout(() => setIntended(true), delayMs);
    };
    const onLeave = () => {
      setHovering(false);
      if (timerRef.current) window.clearTimeout(timerRef.current);
      window.setTimeout(() => setIntended(false), 300); // grace period
    };
    el.addEventListener('mouseenter', onEnter);
    el.addEventListener('mouseleave', onLeave);
    const onEsc = (e: KeyboardEvent) => { if (e.key === 'Escape') { setIntended(false); setHovering(false); } };
    document.addEventListener('keydown', onEsc);
    return () => {
      el.removeEventListener('mouseenter', onEnter);
      el.removeEventListener('mouseleave', onLeave);
      document.removeEventListener('keydown', onEsc);
      if (timerRef.current) window.clearTimeout(timerRef.current);
    };
  }, [ref, delayMs]);
  return { hovering, intended };
}

// HoverPreviewLink.tsx
import { useEffect, useRef, useState } from 'react';
import { useHoverIntent } from './useHoverIntent';
import { getCachedPreview, setCachedPreview } from './previewCache';
import type { LinkPreview } from './types';

interface Props { href: string; children: React.ReactNode; fetchPreview: (url: string, signal: AbortSignal) => Promise<LinkPreview>; }

export function HoverPreviewLink({ href, children, fetchPreview }: Props) {
  const linkRef = useRef<HTMLAnchorElement | null>(null);
  const { intended } = useHoverIntent(linkRef, 350);
  const [preview, setPreview] = useState<LinkPreview | null>(() => getCachedPreview(href));
  const [status, setStatus] = useState<'idle' | 'loading' | 'ready' | 'error'>(preview ? 'ready' : 'idle');
  const abortRef = useRef<AbortController | null>(null);

  useEffect(() => {
    if (!intended || status === 'ready') return;
    if (status === 'loading') return;
    setStatus('loading');
    abortRef.current = new AbortController();
    fetchPreview(href, abortRef.current.signal)
      .then(p => { setCachedPreview(href, p); setPreview(p); setStatus('ready'); })
      .catch((e) => { if ((e as Error).name !== 'AbortError') setStatus('error'); });
    return () => { abortRef.current?.abort(); };
  }, [intended, href, fetchPreview, status]);

  useEffect(() => {
    if (!intended && abortRef.current) abortRef.current.abort();
  }, [intended]);

  const rect = linkRef.current?.getBoundingClientRect();

  return (
    <>
      <a ref={linkRef} href={href} className="text-[oklch(0.55_0.18_250)] underline underline-offset-2 hover:no-underline">{children}</a>
      {intended && rect && (
        <div role="dialog" aria-label="Link preview" className="fixed z-30 w-[320px] bg-white rounded-md shadow-lg border border-[oklch(0.92_0.005_250)] p-3 text-[oklch(0.18_0.005_250)]" style={{ top: rect.bottom + window.scrollY + 8, left: rect.left + window.scrollX, animation: 'previewIn 80ms ease-out' }}>
          {status === 'loading' && (
            <div>
              <div className="h-4 w-3/4 bg-[oklch(0.93_0.005_250)] rounded mb-2" />
              <div className="h-3 w-full bg-[oklch(0.95_0.005_250)] rounded mb-1" />
              <div className="h-3 w-5/6 bg-[oklch(0.95_0.005_250)] rounded" />
            </div>
          )}
          {status === 'ready' && preview && (
            <div className="flex gap-3">
              <div className="flex-1 min-w-0">
                <div className="text-[14px] font-medium truncate flex items-center gap-1.5">
                  {preview.title}
                  {Date.now() - preview.updatedAt < 86400000 && <span aria-label="Recently updated" className="w-1.5 h-1.5 rounded-full bg-[oklch(0.55_0.18_250)]" />}
                </div>
                <p className="text-[13px] text-[oklch(0.45_0.005_250)] mt-1 line-clamp-3">{preview.snippet}</p>
                {preview.author && <div className="text-[11px] text-[oklch(0.55_0.005_250)] mt-1.5">By {preview.author}</div>}
              </div>
              {preview.thumbnail && <img src={preview.thumbnail} alt="" className="w-16 h-16 object-cover rounded" />}
            </div>
          )}
          {status === 'error' && <div className="text-[13px] text-[oklch(0.55_0.16_25)]">Couldn\u2019t load preview</div>}
          <style>{`@keyframes previewIn { from { opacity: 0 } to { opacity: 1 } } @media (prefers-reduced-motion: reduce) { [style*='previewIn'] { animation: none !important } }`}</style>
        </div>
      )}
    </>
  );
}

export function computeQuantiles(values: ReadonlyArray<number>): [number, number, number] {
  const nonZero = values.filter(v => v > 0).sort((a, b) => a - b);
  if (nonZero.length === 0) return [0, 0, 0];
  const q = (p: number) => nonZero[Math.floor(p * nonZero.length)];
  return [q(0.25), q(0.5), q(0.75)];
}

export function bucketFor(value: number, quantiles: [number, number, number]): number {
  if (value === 0) return 0;
  if (value <= quantiles[0]) return 1;
  if (value <= quantiles[1]) return 2;
  if (value <= quantiles[2]) return 3;
  return 4;
}

// CalendarHeatmap.tsx
import { useMemo, useState } from 'react';
import { computeQuantiles, bucketFor } from './quantiles';

export interface Day { date: string; count: number; }

interface Props { days: ReadonlyArray<Day>; hue?: number; onDayClick?: (day: Day) => void; }

export function CalendarHeatmap({ days, hue = 145, onDayClick }: Props) {
  const quantiles = useMemo(() => computeQuantiles(days.map(d => d.count)), [days]);
  const colorForBucket = (b: number): string => {
    if (b === 0) return 'oklch(0.95 0.005 250)';
    const L = [0.92, 0.78, 0.6, 0.42][b - 1];
    const C = [0.04, 0.08, 0.14, 0.18][b - 1];
    return `oklch(${L} ${C} ${hue})`;
  };

  // organize into weeks
  const weeks = useMemo(() => {
    const out: Day[][] = [];
    let current: Day[] = [];
    days.forEach((d, i) => {
      const dow = new Date(d.date).getDay();
      if (dow === 0 && current.length > 0) { out.push(current); current = []; }
      current.push(d);
      if (i === days.length - 1) out.push(current);
    });
    return out;
  }, [days]);

  const [hoverDay, setHoverDay] = useState<Day | null>(null);

  const dayStats = useMemo(() => {
    if (!hoverDay) return null;
    const dow = new Date(hoverDay.date).getDay();
    const sameDayValues = days.filter(d => new Date(d.date).getDay() === dow).map(d => d.count).sort((a, b) => b - a);
    const rank = sameDayValues.indexOf(hoverDay.count) + 1;
    return { rank, dowName: ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][dow] };
  }, [hoverDay, days]);

  return (
    <div className="relative" role="figure" aria-label="Activity calendar heatmap">
      <div className="flex gap-[2px]">
        <div className="flex flex-col justify-around text-[10px] text-[oklch(0.55_0.005_250)] pr-2">
          <span>Mon</span><span>Wed</span><span>Fri</span>
        </div>
        {weeks.map((week, wi) => (
          <div key={wi} className="flex flex-col gap-[2px]">
            {week.map((day, di) => {
              const bucket = bucketFor(day.count, quantiles);
              return (
                <button key={di} type="button" aria-label={`${day.date}: ${day.count}`} onClick={() => onDayClick?.(day)} onMouseEnter={() => setHoverDay(day)} onMouseLeave={() => setHoverDay(null)}
                  className="w-[11px] h-[11px] rounded-sm focus-visible:outline focus-visible:outline-1 focus-visible:outline-[oklch(0.2_0.01_250)]"
                  style={{ background: colorForBucket(bucket) }} />
              );
            })}
          </div>
        ))}
      </div>
      {hoverDay && dayStats && (
        <div role="status" className="absolute top-full mt-2 left-0 bg-[oklch(0.18_0.005_250)] text-white text-[12px] px-3 py-2 rounded shadow-lg" style={{ animation: 'tipIn 80ms ease-out 200ms backwards' }}>
          <div className="font-medium">{new Date(hoverDay.date).toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' })}</div>
          <div className="text-[11px] mt-0.5 opacity-80">{hoverDay.count} {hoverDay.count === 1 ? 'event' : 'events'} \u00B7 #{dayStats.rank} most active {dayStats.dowName} this year</div>
          <style>{`@keyframes tipIn { from { opacity: 0 } to { opacity: 1 } }`}</style>
        </div>
      )}
    </div>
  );
}

import { useCallback, useState } from 'react';
const KEY = 'sandbox-completed-v1';
export function useSandboxCompletion(featureId: string) {
  const [completed, setCompleted] = useState<boolean>(() => {
    try { const arr = JSON.parse(localStorage.getItem(KEY) ?? '[]'); return arr.includes(featureId); } catch { return false; }
  });
  const markComplete = useCallback(() => {
    setCompleted(true);
    try {
      const arr = JSON.parse(localStorage.getItem(KEY) ?? '[]');
      if (!arr.includes(featureId)) localStorage.setItem(KEY, JSON.stringify([...arr, featureId]));
    } catch {}
  }, [featureId]);
  return { completed, markComplete };
}

