            </div>
          )}
          <style>{`@keyframes sandboxIn { from { opacity: 0; max-height: 0 } to { opacity: 1; max-height: 400px } } @keyframes checkDraw { from { stroke-dashoffset: 20 } to { stroke-dashoffset: 0 } } @media (prefers-reduced-motion: reduce) { [style*='sandboxIn'], [style*='checkDraw'] { animation: none !important } }`}</style>
        </div>
      )}
    </div>
  );
}

